/**
 * Izračun kalorij z MET formulo:
 *   kcal = MET × težaKg × čas_v_urah
 * Doda pribitek za vzpon: ~1 kcal/m vzpona (standardna ocena).
 */
private fun calculateCaloriesMet(
    activityType: ActivityType,
    durationSeconds: Long,
    weightKg: Double,
    elevationGainM: Float,
    avgSpeedKmh: Float
): Int {
    // 1. Omejimo nerealne hitrosti do 35 km/h za tek (GPS skoki)
    val safeSpeed = avgSpeedKmh.coerceIn(0f, 35f)

    // Prilagodi MET glede na hitrost z linearno interpolacijo,
    // da preprečimo stopničaste "GPS skoke" ki umetno dvignejo MET.
    val met = when (activityType) {
        ActivityType.RUN -> when {
            safeSpeed < 4f  -> safeSpeed // Linearno od 0 do 4
            safeSpeed < 8f  -> 4.0 + (safeSpeed - 4f) * 0.5 // 4 do 6
            safeSpeed < 10f -> 6.0 + (safeSpeed - 8f) * 1.0 // 6 do 8
            safeSpeed < 12f -> 8.0 + (safeSpeed - 10f) * 1.0 // 8 do 10
            safeSpeed < 14f -> 10.0 + (safeSpeed - 12f) * 0.75 // 10 do 11.5
            else            -> 11.5 + (safeSpeed - 14f) * 0.4
        }
        ActivityType.WALK -> when {
            safeSpeed < 3f -> 2.0 + (safeSpeed / 3f) * 0.5 // do 2.5
            safeSpeed < 5f -> 2.5 + (safeSpeed - 3f) * 0.5 // 2.5 do 3.5
            safeSpeed < 7f -> 3.5 + (safeSpeed - 5f) * 0.5 // 3.5 do 4.5
            else           -> 4.5 + (safeSpeed - 7f) * 0.3
        }
        ActivityType.SPRINT -> when {
            safeSpeed < 10f -> 8.0
            safeSpeed < 16f -> 8.0 + (safeSpeed - 10f) * 0.83 // 8 do 13
            safeSpeed < 20f -> 13.0 + (safeSpeed - 16f) * 0.75 // 13 do 16
            else            -> 16.0 + (safeSpeed - 20f) * 0.5
        }
        ActivityType.HIKE -> 6.0 + (elevationGainM / 100f) * 0.5 // Base 6.0 + gain
        ActivityType.CYCLING -> when {
            safeSpeed < 15f -> 4.0
            safeSpeed < 20f -> 6.0
            safeSpeed < 25f -> 8.0
            else            -> 10.0
        }
        else -> 5.0
    }.toDouble()

    // 2. Trajanje v urah
    val hours = durationSeconds / 3600.0
    // 3. Težo omejimo med 30kg in 200kg zaradi napak v profilu
    val safeWeight = weightKg.coerceIn(30.0, 200.0)

    val base = met * safeWeight * hours
    // Vzpon: ~0.8 kcal/m za povprečno težo 70 kg, skalira z dejansko težo. Omejen poskok GPS baz (max 2000m na log).
    val safeElevation = elevationGainM.coerceIn(0f, 2000f)
    val elevBonus = safeElevation * 0.8 * (safeWeight / 70.0)
    return (base + elevBonus).toInt().coerceAtLeast(0)
}

private fun calculateXP(activityType: ActivityType, distanceMeters: Double, timeSeconds: Long): Int {
    val baseFromDistance = distanceMeters / 100.0
    val baseFromTime = timeSeconds / 60.0
    val multiplier = when (activityType) {
        ActivityType.RUN, ActivityType.SPRINT -> 1.5
        ActivityType.HIKE, ActivityType.NORDIC -> 1.3
        ActivityType.WALK -> 1.0
        ActivityType.CYCLING -> 0.6
        ActivityType.SKIING, ActivityType.SNOWBOARD -> 0.5
        ActivityType.SKATING -> 1.0
    }
    return ((baseFromDistance + baseFromTime) * multiplier).toInt().coerceAtLeast(10)
}

@Composable
fun RunTrackerScreen(onBackPressed: () -> Unit, userProfile: UserProfile = UserProfile()) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    LaunchedEffect(Unit) {
        val config = Configuration.getInstance()
        config.userAgentValue = context.packageName
        config.cacheMapTileCount = 16.toShort()
        config.cacheMapTileOvershoot = 16.toShort()
    }

    // --- Tip aktivnosti ---
    var selectedActivity by remember { mutableStateOf(ActivityType.RUN) }
    var showActivityPicker by remember { mutableStateOf(false) }

    var service by remember { mutableStateOf<RunTrackingService?>(null) }
    var isBound by remember { mutableStateOf(false) }
    var isTracking by remember { mutableStateOf(false) }
    var isPaused by remember { mutableStateOf(false) }
    var locationPoints by remember { mutableStateOf<List<Location>>(emptyList()) }
    var elapsedSeconds by remember { mutableStateOf(0L) }
    var distanceMeters by remember { mutableStateOf(0.0) }
    var maxSpeed by remember { mutableStateOf(0f) }
    var avgSpeed by remember { mutableStateOf(0f) }
    var elevationGain by remember { mutableStateOf(0f) }
    var elevationLoss by remember { mutableStateOf(0f) }
    var mapView by remember { mutableStateOf<MapView?>(null) }
    var myLocationOverlay by remember { mutableStateOf<MyLocationNewOverlay?>(null) }
    var hasLocationPermission by remember { mutableStateOf(false) }
    var hasNotificationPermission by remember { mutableStateOf(true) }
    var showGpsDialog by remember { mutableStateOf(false) }
    var showDiscardDialog by remember { mutableStateOf(false) }
    var showSummary by remember { mutableStateOf(false) }
    var isSavingActivity by remember { mutableStateOf(false) }
    var routePolyline by remember { mutableStateOf<Polyline?>(null) }
    var isMapFollowingTarget by remember { mutableStateOf(true) }
    var finalDistance by remember { mutableStateOf(0.0) }
    var finalTime by remember { mutableStateOf(0L) }
    var finalMaxSpeed by remember { mutableStateOf(0f) }
    var finalAvgSpeed by remember { mutableStateOf(0f) }
    var finalElevationGain by remember { mutableStateOf(0f) }
    var finalElevationLoss by remember { mutableStateOf(0f) }
    var actualWeightKg by remember { mutableStateOf(70.0) }
    val uid = remember { com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId() }

    LaunchedEffect(uid) {
        if (uid != null) {
            try {
                Firebase.firestore.collection("users").document(uid)
                    .collection("weightLogs")
                    .orderBy("date", com.google.firebase.firestore.Query.Direction.DESCENDING)
                    .limit(1).get()
                    .addOnSuccessListener { snap ->
                        val w = snap.documents.firstOrNull()?.get("weightKg") as? Number
                        if (w != null) actualWeightKg = w.toDouble()
                    }
            } catch (_: Exception) {}
        }
    }

    val serviceConnection = remember {
        object : ServiceConnection {
            override fun onServiceConnected(name: ComponentName?, binder: IBinder?) {
                service = (binder as? RunTrackingService.LocalBinder)?.getService(); isBound = true
            }
            override fun onServiceDisconnected(name: ComponentName?) { service = null; isBound = false }
        }
    }

    LaunchedEffect(Unit) { context.bindService(Intent(context, RunTrackingService::class.java), serviceConnection, Context.BIND_AUTO_CREATE) }
    DisposableEffect(Unit) {
        onDispose {
            if (isBound) try { context.unbindService(serviceConnection) } catch (_: Exception) {}
            myLocationOverlay?.disableMyLocation(); myLocationOverlay?.disableFollowLocation(); mapView?.onDetach()
        }
    }
    LaunchedEffect(service) { service?.isTracking?.collect { isTracking = it } }
    LaunchedEffect(service) { service?.isPaused?.collect { isPaused = it } }
    LaunchedEffect(service) { service?.locationPoints?.collect { locationPoints = it } }
    LaunchedEffect(service) { service?.elapsedSeconds?.collect { elapsedSeconds = it } }
    LaunchedEffect(service) { service?.distanceMeters?.collect { distanceMeters = it } }
    LaunchedEffect(service) { service?.maxSpeed?.collect { maxSpeed = it } }
    LaunchedEffect(service) { service?.avgSpeed?.collect { avgSpeed = it } }
    LaunchedEffect(service) { service?.elevationGain?.collect { elevationGain = it } }
    LaunchedEffect(service) { service?.elevationLoss?.collect { elevationLoss = it } }

    LaunchedEffect(Unit) {
        hasLocationPermission = ContextCompat.checkSelfPermission(context, Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED
        hasNotificationPermission = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU)
            ContextCompat.checkSelfPermission(context, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED else true
    }

    val locationPermissionLauncher = rememberLauncherForActivityResult(ActivityResultContracts.RequestPermission()) { hasLocationPermission = it }
    val notificationPermissionLauncher = rememberLauncherForActivityResult(ActivityResultContracts.RequestPermission()) { hasNotificationPermission = it }

    val prefs = context.getSharedPreferences("app_settings", Context.MODE_PRIVATE)
    var routeSmoothingEnabled by remember { mutableStateOf(prefs.getBoolean("route_smoothing", true)) }

    var isTopoMap by remember { mutableStateOf(prefs.getBoolean("topo_map", false)) }

    // Live kcal (prikazano med sledenjem)
    val liveCalories = remember(elapsedSeconds, avgSpeed, elevationGain, selectedActivity, actualWeightKg) {
        calculateCaloriesMet(selectedActivity, elapsedSeconds, actualWeightKg, elevationGain, avgSpeed * 3.6f)
    }

    LaunchedEffect(locationPoints) {
        mapView?.let { map ->
            routePolyline?.let { map.overlays.remove(it) }
            if (locationPoints.isNotEmpty()) {
                val polyline = Polyline(map).apply {
                    outlinePaint.color = android.graphics.Color.rgb(33, 150, 243)
                    outlinePaint.strokeWidth = 12f
                    outlinePaint.strokeCap = android.graphics.Paint.Cap.ROUND
                    outlinePaint.isAntiAlias = true
                    setPoints(locationPoints.map { GeoPoint(it.latitude, it.longitude) })
                }
                map.overlays.add(polyline); routePolyline = polyline

                if (isMapFollowingTarget) {
                    map.controller.animateTo(GeoPoint(locationPoints.last().latitude, locationPoints.last().longitude))
                }

                if (map.zoomLevelDouble < 16.0) map.controller.setZoom(17.0)
                map.invalidate()
            }
        }
    }

    val onMapTouch = {
        if (isMapFollowingTarget) isMapFollowingTarget = false
    }

    Box(Modifier.fillMaxSize().background(MaterialTheme.colorScheme.background)) {
        // Mapa
        AndroidView(
            factory = { ctx ->
                MapView(ctx).apply {
                    setTileSource(if (isTopoMap) TileSourceFactory.OpenTopo else TileSourceFactory.MAPNIK)
                    setMultiTouchControls(true); controller.setZoom(17.0)
                    val overlay = MyLocationNewOverlay(GpsMyLocationProvider(ctx), this).apply {
                        enableMyLocation(); enableFollowLocation(); setDrawAccuracyEnabled(true)
                    }
                    overlays.add(overlay); myLocationOverlay = overlay
                    controller.setCenter(GeoPoint(46.0569, 14.5058))
                    overlay.runOnFirstFix { post { overlay.myLocation?.let { controller.animateTo(it) } } }
                    mapView = this

                    setOnTouchListener { v, event ->
                        if (event.action == android.view.MotionEvent.ACTION_DOWN || event.action == android.view.MotionEvent.ACTION_MOVE) {
                            onMapTouch()
                            overlay.disableFollowLocation()
                        }
                        v.performClick()
                        false
                    }
                }
            },
            modifier = Modifier.fillMaxSize(),
            update = { map ->
                map.onResume()
                val currentSource = if (isTopoMap) TileSourceFactory.OpenTopo else TileSourceFactory.MAPNIK
                if (map.tileProvider.tileSource != currentSource) {
                    map.setTileSource(currentSource)
                }

                map.overlayManager.tilesOverlay.setColorFilter(null)
            }
        )

        // Map Type Toggle (vedno na istem mestu, zgoraj desno, nad re-center)
        SmallFloatingActionButton(
            onClick = {
                isTopoMap = !isTopoMap
                prefs.edit().putBoolean("topo_map", isTopoMap).apply()
            },
            modifier = Modifier
                .align(Alignment.TopEnd)
                .padding(16.dp),
            containerColor = MaterialTheme.colorScheme.surfaceVariant,
            contentColor = MaterialTheme.colorScheme.onSurfaceVariant
        ) {
            Icon(Icons.Filled.Map, contentDescription = "Toggle Map Type")
        }

        // Re-center button (pod gumbom za tip mape)
        if (!isMapFollowingTarget) {
            SmallFloatingActionButton(
                onClick = {
                    isMapFollowingTarget = true
                    myLocationOverlay?.enableFollowLocation()
                    locationPoints.lastOrNull()?.let {
                        mapView?.controller?.animateTo(GeoPoint(it.latitude, it.longitude))
                    }
                },
                modifier = Modifier
                    .align(Alignment.TopEnd)
                    .padding(top = 72.dp, end = 16.dp),
                containerColor = MaterialTheme.colorScheme.primary,
                contentColor = MaterialTheme.colorScheme.onPrimary
            ) {
                Icon(Icons.Filled.MyLocation, contentDescription = "Re-center map")
            }
        }

        // Stats card (levo zgoraj)
        Card(
            Modifier.align(Alignment.TopStart).padding(16.dp).fillMaxWidth(0.58f),
            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f)),
            shape = RoundedCornerShape(12.dp)
        ) {
            Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(5.dp)) {
                IconButton(onClick = onBackPressed, modifier = Modifier.align(Alignment.Start)) {
                    Icon(Icons.AutoMirrored.Filled.ArrowBack, "Back", tint = MaterialTheme.colorScheme.onSurface)
                }

                // Tip aktivnosti oznaka (med sledenjem — ne gumb)
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Text(
                        "${selectedActivity.emoji} ${selectedActivity.label}",
                        fontSize = 13.sp,
                        fontWeight = FontWeight.SemiBold,
                        color = MaterialTheme.colorScheme.primary
                    )
                    if (isTracking) {
                        Spacer(Modifier.width(8.dp))
                        val (gpsProfile, gpsColor) = when (selectedActivity) {
                            ActivityType.SPRINT, ActivityType.RUN -> "High accuracy" to Color(0xFF4CAF50)
                            ActivityType.CYCLING, ActivityType.SKIING, ActivityType.SNOWBOARD, ActivityType.SKATING -> "Balanced" to MaterialTheme.colorScheme.tertiary
                            ActivityType.WALK, ActivityType.HIKE, ActivityType.NORDIC -> "Battery saver" to Color(0xFF9E9E9E)
                        }
                        Surface(
                            color = gpsColor.copy(alpha = 0.1f),
                            shape = RoundedCornerShape(4.dp),
                            border = androidx.compose.foundation.BorderStroke(1.dp, gpsColor.copy(alpha = 0.5f))
                        ) {
                            Text(
                                text = "GPS: $gpsProfile",
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Medium,
                                color = gpsColor,
                                modifier = Modifier.padding(horizontal = 4.dp, vertical = 2.dp)
                            )
                        }
                    }
                }

                Text("${"%.2f".format(distanceMeters / 1000.0)} km", fontSize = 18.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onSurface)
                Text(fmtTime(elapsedSeconds), fontSize = 16.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onSurface)

                if (selectedActivity.showSpeed) {
                    Text("Max: ${"%.1f".format(maxSpeed * 3.6)} km/h", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                    Text("Avg: ${"%.1f".format(avgSpeed * 3.6)} km/h", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                }
                if (selectedActivity.showPace && distanceMeters > 50) {
                    val paceMin = if (avgSpeed > 0.1f) (1000.0 / (avgSpeed * 60.0)) else 0.0
                    Text("Pace: ${paceMin.toInt()}:${"%02d".format(((paceMin - paceMin.toInt()) * 60).toInt())} /km", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurface)
                }
                if (selectedActivity.showElevation && (elevationGain > 0f || elevationLoss > 0f)) {
                    Text("↑ ${"%.0f".format(elevationGain)} m  ↓ ${"%.0f".format(elevationLoss)} m", fontSize = 13.sp, color = Color(0xFF4CAF50))
                }
                if (isTracking) {
                    Text(" $liveCalories kcal", fontSize = 13.sp, fontWeight = FontWeight.Medium, color = MaterialTheme.colorScheme.tertiary)
                    Text(
                        if (isPaused) "Paused" else "Tracking...",
                        fontSize = 12.sp,
                        color = if (isPaused) MaterialTheme.colorScheme.tertiary else Color(0xFF4CAF50),
                        fontWeight = FontWeight.Medium
                    )
                }
            }
        }

        // Controls card (spodaj)
        Card(
            Modifier.align(Alignment.BottomCenter).padding(16.dp).fillMaxWidth(),
            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f)),
            shape = RoundedCornerShape(16.dp)
        ) {
            Column(Modifier.padding(horizontal = 16.dp, vertical = 12.dp)) {
                // --- Picker aktivnosti (samo ko ne sledimo) ---
                if (!isTracking && !showSummary) {
                    // Izbrani tip + gumb za spremembo
                    Row(
                        Modifier
                            .fillMaxWidth()
                            .clickable { showActivityPicker = !showActivityPicker }
                            .background(MaterialTheme.colorScheme.surfaceVariant, RoundedCornerShape(10.dp))
                            .padding(horizontal = 14.dp, vertical = 8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            "${selectedActivity.emoji} ${selectedActivity.label}",
                            fontSize = 15.sp,
                            fontWeight = FontWeight.SemiBold,
                            color = MaterialTheme.colorScheme.onSurface,
                            modifier = Modifier.weight(1f)
                        )
                        Icon(Icons.Filled.ArrowDropDown, "Izberi aktivnost", tint = MaterialTheme.colorScheme.primary)
                    }

                    // Picker lista — horizontalni scroll
                    if (showActivityPicker) {
                        Spacer(Modifier.height(8.dp))
                        LazyRow(
                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                            contentPadding = PaddingValues(horizontal = 2.dp)
                        ) {
                            items(items = ActivityType.entries, key = { it.name }) { type ->
                                val isSelected = type == selectedActivity
                                Surface(
                                    shape = RoundedCornerShape(20.dp),
                                    color = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.surfaceVariant,
                                    modifier = Modifier.clickable {
                                        selectedActivity = type
                                        showActivityPicker = false
                                    }
                                ) {
                                    Text(
                                        "${type.emoji} ${type.label}",
                                        modifier = Modifier.padding(horizontal = 12.dp, vertical = 8.dp),
                                        fontSize = 13.sp,
                                        fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                                        color = if (isSelected) Color.White else MaterialTheme.colorScheme.onSurface
                                    )
                                }
                            }
                        }
                        Spacer(Modifier.height(8.dp))
                    }
                    Spacer(Modifier.height(8.dp))
                }

                // Gumbi
                Row(
                    Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(12.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    when {
                        !isTracking && !showSummary -> Button(
                            onClick = {
                                when {
                                    !hasLocationPermission -> locationPermissionLauncher.launch(Manifest.permission.ACCESS_FINE_LOCATION)
                                    !hasNotificationPermission && Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU ->
                                        notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                                    else -> {
                                        val locationManager = context.getSystemService(Context.LOCATION_SERVICE) as LocationManager
                                        if (!locationManager.isProviderEnabled(LocationManager.GPS_PROVIDER)) {
                                            showGpsDialog = true
                                        } else {
                                            showActivityPicker = false
                                            context.startForegroundService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_START })
                                        }
                                    }
                                }
                            },
                            modifier = Modifier.weight(1f).height(56.dp),
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF4CAF50)),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Icon(Icons.Filled.PlayArrow, null)
                            Spacer(Modifier.width(8.dp))
                            Text("Start ${selectedActivity.label}", fontSize = 16.sp, fontWeight = FontWeight.Bold)
                        }

                        isTracking -> {
                            Button(
                                onClick = { context.startService(Intent(context, RunTrackingService::class.java).apply { action = if (isPaused) RunTrackingService.ACTION_RESUME else RunTrackingService.ACTION_PAUSE }) },
                                modifier = Modifier.weight(1f).height(56.dp),
                                colors = ButtonDefaults.buttonColors(containerColor = if (isPaused) Color(0xFF4CAF50) else MaterialTheme.colorScheme.tertiary),
                                shape = RoundedCornerShape(12.dp)
                            ) { Icon(if (isPaused) Icons.Filled.PlayArrow else Icons.Filled.Pause, null); Spacer(Modifier.width(8.dp)); Text(if (isPaused) "Resume" else "Pause", fontSize = 16.sp, fontWeight = FontWeight.Bold) }

                            Button(
                                onClick = {
                                    if (distanceMeters < 20.0) {
                                        context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_PAUSE })
                                        showDiscardDialog = true
                                        return@Button
                                    }

                                    finalDistance = distanceMeters; finalTime = elapsedSeconds
                                    finalMaxSpeed = maxSpeed; finalAvgSpeed = avgSpeed
                                    finalElevationGain = elevationGain; finalElevationLoss = elevationLoss

                                    // ADDED: Samodejni predlog aktivnosti na podlagi hitrosti
                                    val currentAvgKmh = avgSpeed * 3.6f
                                    if (finalDistance > 100 && currentAvgKmh > 0) {
                                        if (selectedActivity == ActivityType.RUN && currentAvgKmh < 6.0f) {
                                            selectedActivity = ActivityType.WALK
                                            com.example.myapplication.utils.AppToast.showSuccess(context, "Activity changed to Walk based on speed (${String.format(java.util.Locale.US, "%.1f", currentAvgKmh)} km/h)")
                                        } else if (selectedActivity == ActivityType.WALK && currentAvgKmh > 7.5f) {
                                            selectedActivity = ActivityType.RUN
                                            com.example.myapplication.utils.AppToast.showSuccess(context, "Activity changed to Run based on speed (${String.format(java.util.Locale.US, "%.1f", currentAvgKmh)} km/h)")
                                        }
                                    }

                                    context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_STOP })

                                    showSummary = true
                                },
                                modifier = Modifier.weight(1f).height(56.dp),
                                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFFF44336)),
                                shape = RoundedCornerShape(12.dp)
                            ) { Icon(Icons.Filled.Stop, null); Spacer(Modifier.width(8.dp)); Text("Stop", fontSize = 16.sp, fontWeight = FontWeight.Bold) }
                        }

                        showSummary -> Spacer(Modifier.height(56.dp))
                    }
                }
            }
        }

        // Summary overlay
        if (showSummary) {
            val xpEarned = calculateXP(selectedActivity, finalDistance, finalTime)

            Box(Modifier.fillMaxSize().background(Color.Black.copy(alpha = 0.6f))) {
                Card(
                    Modifier.align(Alignment.Center).fillMaxWidth(0.88f),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                    shape = RoundedCornerShape(20.dp)
                ) {
                    Column(
                        Modifier.padding(24.dp).fillMaxWidth(),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Text(
                            "${selectedActivity.emoji} ${selectedActivity.label} Complete!",
                            fontSize = 22.sp, fontWeight = FontWeight.Bold,
                            color = MaterialTheme.colorScheme.primary
                        )
                        HorizontalDivider()

                        SummaryRow(" Distance", "${"%.2f".format(finalDistance / 1000.0)} km")
                        SummaryRow("⏱️ Duration", fmtTime(finalTime))

                        if (selectedActivity.showSpeed) {
                            SummaryRow("⚡ Max speed", "${"%.1f".format(finalMaxSpeed * 3.6)} km/h")
                            SummaryRow(" Avg speed", "${"%.1f".format(finalAvgSpeed * 3.6)} km/h")
                        }
                        if (selectedActivity.showPace && finalDistance > 50) {
                            val p = (finalTime / 60.0) / (finalDistance / 1000.0)
                            SummaryRow(" Pace", "${p.toInt()}:${"%02d".format(((p - p.toInt()) * 60).toInt())} /km")
                        }
                        if (selectedActivity.showElevation && (finalElevationGain > 0f || finalElevationLoss > 0f)) {
                            SummaryRow("⛰️ Ascent", "${"%.0f".format(finalElevationGain)} m")
                            SummaryRow("↘️ Descent", "${"%.0f".format(finalElevationLoss)} m")
                        }

                        SummaryRow(" XP Earned", "$xpEarned XP", highlight = true)

                        HorizontalDivider()
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Checkbox(
                                checked = routeSmoothingEnabled,
                                onCheckedChange = {
                                    routeSmoothingEnabled = it
                                    prefs.edit().putBoolean("route_smoothing", it).apply()
                                }
                            )
                            Text("Route smoothing (Snap-to-road)", fontSize = 14.sp)
                        }

                        Button(
                            onClick = {
                                if (isSavingActivity) return@Button
                                isSavingActivity = true
                                val sessionId = java.util.UUID.randomUUID().toString()
                                val avgKmh = finalAvgSpeed * 3.6f
                                val calories = calculateCaloriesMet(selectedActivity, finalTime, actualWeightKg, finalElevationGain, avgKmh)

                                scope.launch(Dispatchers.IO) {
                                    val mappedLocationPoints = locationPoints.map { loc ->
                                        com.example.myapplication.data.LocationPoint(
                                            latitude = loc.latitude,
                                            longitude = loc.longitude,
                                            altitude = loc.altitude,
                                            speed = loc.speed,
                                            accuracy = loc.accuracy,
                                            timestamp = loc.time
                                        )
                                    }

                                    var finalLocationPoints = mappedLocationPoints
                                    var successfullySmoothed = false
                                    if (routeSmoothingEnabled) {
                                        val isWalkingProfile = selectedActivity == ActivityType.RUN || selectedActivity == ActivityType.WALK || selectedActivity == ActivityType.HIKE
                                        // Opravimo glajenje poti za vgrajene tipe
                                        if (isWalkingProfile || selectedActivity == ActivityType.CYCLING || selectedActivity == ActivityType.SPRINT) {
                                            finalLocationPoints = com.example.myapplication.map.MapboxMapMatcher.matchRoute(mappedLocationPoints, isWalkingProfile)
                                            if (finalLocationPoints !== mappedLocationPoints) {
                                                successfullySmoothed = true
                                            }
                                        }
                                    }

                                    if (uid != null) {
                                        val avgSpeedMps = if (finalTime > 0) (finalDistance / finalTime).toFloat() else 0f
                                        val runMap = hashMapOf<String, Any>(
                                            "id" to sessionId, "userId" to uid,
                                            "startTime" to (System.currentTimeMillis() - finalTime * 1000L),
                                            "endTime" to System.currentTimeMillis(),
                                            "durationSeconds" to finalTime.toInt(),
                                            "distanceMeters" to finalDistance,
                                            "maxSpeedMps" to finalMaxSpeed,
                                            "avgSpeedMps" to avgSpeedMps,
                                            "caloriesKcal" to calories,
                                            "elevationGainM" to finalElevationGain,
                                            "elevationLossM" to finalElevationLoss,
                                            "activityType" to selectedActivity.name,
                                            "createdAt" to System.currentTimeMillis(),
                                            "polylinePoints" to emptyList<Any>(),
                                            "isSmoothed" to successfullySmoothed
                                        )
                                        Firebase.firestore
                                            .collection("users").document(uid)
                                            .collection("runSessions").document(sessionId)
                                            .set(runMap)

                                        val email = com.google.firebase.auth.FirebaseAuth.getInstance().currentUser?.email
                                        if (email != null) {
                                            val shareActSnap = Firebase.firestore.collection("users").document(uid).get().await()
                                            val shareAct = shareActSnap.getBoolean("share_activities") ?: false
                                            if (shareAct && finalLocationPoints.isNotEmpty()) {
                                                val rawPts = finalLocationPoints.map { Pair(it.latitude, it.longitude) }
                                                val compressed = com.example.myapplication.utils.RouteCompressor.compress(rawPts)
                                                val routeList = compressed.map { (lat, lng) -> mapOf("lat" to lat, "lng" to lng) }
                                                val pubMap = hashMapOf<String, Any>(
                                                    "activityType" to selectedActivity.name,
                                                    "distanceMeters" to finalDistance,
                                                    "elevationGainM" to finalElevationGain,
                                                    "elevationLossM" to finalElevationLoss,
                                                    "avgSpeedMps" to avgSpeedMps,
                                                    "maxSpeedMps" to finalMaxSpeed,
                                                    "startTime" to (System.currentTimeMillis() - finalTime * 1000L),
                                                    "routePoints" to routeList
                                                )
                                                Firebase.firestore
                                                    .collection("users").document(uid)
                                                    .collection("publicActivities").document(sessionId)
                                                    .set(pubMap)
                                            }
                                        }
                                    }

                                    // VEDNO shranimo originalne (raw) točke, da ohranimo pravilen hitrostni graf in meritve!
                                    if (mappedLocationPoints.isNotEmpty()) {
                                        com.example.myapplication.persistence.RunRouteStore.saveRoute(context, sessionId, mappedLocationPoints)
                                    }
                                    // Če je glajenje uspelo, shranimo dodaten file samo za risanje čudovite poti na mapi
                                    if (successfullySmoothed && finalLocationPoints.isNotEmpty()) {
                                        com.example.myapplication.persistence.RunRouteStore.saveRoute(context, sessionId + "_smoothed", finalLocationPoints)
                                    }

                                    val xp = calculateXP(selectedActivity, finalDistance, finalTime)
                                    val runEmail = com.google.firebase.auth.FirebaseAuth.getInstance().currentUser?.email
                                    if (runEmail != null) {
                                        com.example.myapplication.persistence.AchievementStore.awardXP(
                                            context, runEmail, xp,
                                            com.example.myapplication.data.XPSource.RUN_COMPLETED,
                                            "Completed ${selectedActivity.label}: ${finalDistance.toInt()}m"
                                        )

                                        val app = context.applicationContext as android.app.Application
                                        val bodyVm = androidx.lifecycle.ViewModelProvider.AndroidViewModelFactory.getInstance(app)
                                            .create(com.example.myapplication.viewmodels.BodyModuleHomeViewModel::class.java)
                                        val uiState = bodyVm.ui.value
                                        val currentDay = uiState.planDay
                                        if (!uiState.isWorkoutDoneToday && !uiState.todayIsRest && finalDistance > 1000) {
                                            bodyVm.completeWorkoutSession(
                                                isExtraWorkout = false,
                                                totalKcal = calories,
                                                totalTimeMin = finalTime / 60.0
                                            )
                                            withContext(Dispatchers.Main) {
                                                com.example.myapplication.utils.AppToast.showSuccess(context, "Workout Day $currentDay Complete! +$xp XP!")
                                            }
                                        } else {
                                            withContext(Dispatchers.Main) {
                                                com.example.myapplication.utils.AppToast.showSuccess(context, "+$xp XP!")
                                            }
                                        }
                                    }
                                    withContext(Dispatchers.Main) {
                                        showSummary = false; onBackPressed()
                                    }
                                }
                            },
                            modifier = Modifier.fillMaxWidth(0.8f).height(50.dp),
                            enabled = !isSavingActivity,
                            colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.primary),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            if (isSavingActivity) {
                                CircularProgressIndicator(modifier = Modifier.size(24.dp), color = MaterialTheme.colorScheme.onPrimary)
                            } else {
                                Text("Done", fontSize = 18.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }
                }
            }
        }
    }

    if (showGpsDialog) {
        AlertDialog(
            onDismissRequest = { showGpsDialog = false },
            title = { Text("GPS ni vklopljen", fontWeight = FontWeight.Bold) },
            text = { Text("Za sledenje aktivnosti potrebuješ vklopljeno lokacijo (GPS). Prosimo vklopi lokacijo v nastavitvah naprave.") },
            confirmButton = {
                TextButton(onClick = {
                    showGpsDialog = false
                    context.startActivity(Intent(Settings.ACTION_LOCATION_SOURCE_SETTINGS))
                }) { Text("Odpri nastavitve") }
            },
            dismissButton = { TextButton(onClick = { showGpsDialog = false }) { Text("Prekliči") } }
        )
    }

    if (showDiscardDialog) {
        AlertDialog(
            onDismissRequest = { showDiscardDialog = false },
            title = { Text("Activity Too Short", fontWeight = FontWeight.Bold) },
            text = { Text("You have recorded less than 20m. Your activity will not be saved if you finish now. Do you want to discard it?") },
            confirmButton = {
                TextButton(onClick = {
                    showDiscardDialog = false
                    context.startService(Intent(context, RunTrackingService::class.java).apply { action = RunTrackingService.ACTION_STOP })
                    onBackPressed()
                }) { Text("Discard", color = MaterialTheme.colorScheme.error) }
            },
            dismissButton = {
                TextButton(onClick = { showDiscardDialog = false }) { Text("Cancel") }
            }
        )
    }
}

@Composable
private fun SummaryRow(label: String, value: String, highlight: Boolean = false) {
    Row(
        Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Text(label, fontSize = 15.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
        Text(
            value,
            fontSize = if (highlight) 17.sp else 15.sp,
            fontWeight = if (highlight) FontWeight.Bold else FontWeight.Medium,
            color = if (highlight) MaterialTheme.colorScheme.tertiary else MaterialTheme.colorScheme.onSurface
        )
    }
}

private fun fmtTime(s: Long) = if (s >= 3600) "%d:%02d:%02d".format(s / 3600, (s % 3600) / 60, s % 60) else "%02d:%02d".format(s / 60, s % 60)

package com.example.myapplication.data.local
import android.content.Context import androidx.room.Database import androidx.room.Room import androidx.room.RoomDatabase import com.example.myapplication.data.local.doo.GpsPointDao import com.example.myapplication.data.local.doo.WorkoutSessionDao import com.example.myapplication.data.local.entity.GpsPointEntity import com.example.myapplication.data.local.entity.WorkoutSessionEntity
/** * AppDatabase — Room baza podatkov za Offline-First strategijo (Faza 3). * * Tabele: * - workout_sessions: povzetki aktivnosti (id = Firestore doc.id kot PK) * - gps_points: GPS koordinate (lokalni surovi podatki ali Firestore kompresija) * * Verzija: 1 (začetna) * Ime datoteke: glow_upp_offline.db */ @Database( entities = [WorkoutSessionEntity::class, GpsPointEntity::class], version = 2, exportSchema = false ) abstract class AppDatabase : RoomDatabase() {
abstract fun workoutSessionDao(): WorkoutSessionDao abstract fun gpsPointDao(): GpsPointDao
companion object { @Volatile private var INSTANCE: AppDatabase? = null
fun getInstance(context: Context): AppDatabase = INSTANCE ?: synchronized(this) { INSTANCE ?: Room.databaseBuilder( context.applicationContext, AppDatabase::class.java, "glow_upp_offline.db" ) .fallbackToDestructiveMigration() // V1: dev/beta — pri spremembi sheme obnovi DB .build() .also { INSTANCE = it } } } }

package com.example.myapplication.data.local
import android.content.Context import androidx.room.Database import androidx.room.Room import androidx.room.RoomDatabase import androidx.room.migration.Migration import androidx.sqlite.db.SupportSQLiteDatabase import com.example.myapplication.data.local.doo.GpsPointDao import com.example.myapplication.data.local.doo.WorkoutSessionDao import com.example.myapplication.data.local.entity.GpsPointEntity import com.example.myapplication.data.local.entity.WorkoutSessionEntity
/** * AppDatabase — Room baza podatkov za Offline-First strategijo (Faza 3). * * Tabele: * - workout_sessions: povzetki aktivnosti (id = Firestore doc.id kot PK) * - gps_points: GPS koordinate (lokalni surovi podatki ali Firestore kompresija) * * Zgodovina verzij: * v1 → Faza 3: začetna shema (workout_sessions, gps_points brez status polja) * v2 → Faza 15: dodan stolpec status TEXT NOT NULL DEFAULT 'COMPLETED' v workout_sessions * (obnova po OOM kill — IN_PROGRESS seje preživijo restart servisa) * * Ime datoteke: glow_upp_offline.db * * ⚠️ FIX (Faza 31.8): Dodan MIGRATION_1_2 — prepreči izbris IN_PROGRESS sej med schema upgradami. * fallbackToDestructiveMigration() ostane kot zadnja varovalka za nepričakovane bodoče napake. */ @Database( entities = [WorkoutSessionEntity::class, GpsPointEntity::class], version = 2, exportSchema = false ) abstract class AppDatabase : RoomDatabase() {
abstract fun workoutSessionDao(): WorkoutSessionDao abstract fun gpsPointDao(): GpsPointDao
companion object {
/** * Migracija v1 → v2: dodan stolpec `status` v `workout_sessions`. * ALTER TABLE + DEFAULT 'COMPLETED' ohrani vse obstoječe vrstice (teki) nedotaknjene. * Brez te migracije je Room izbrisal celotno bazo — IN_PROGRESS (aktivni tek) je bil izgubljen. */ private val MIGRATION_1_2 = object : Migration(1, 2) { override fun migrate(db: SupportSQLiteDatabase) { db.execSQL( "ALTER TABLE workout_sessions ADD COLUMN status TEXT NOT NULL DEFAULT 'COMPLETED'" ) } }
@Volatile private var INSTANCE: AppDatabase? = null
fun getInstance(context: Context): AppDatabase = INSTANCE ?: synchronized(this) { INSTANCE ?: Room.databaseBuilder( context.applicationContext, AppDatabase::class.java, "glow_upp_offline.db" ) .addMigrations(MIGRATION_1_2) // v1→v2: ohrani aktivne seje (IN_PROGRESS) .fallbackToDestructiveMigration(true) // zadnja varovalka za nepričakovane prihodnje napake .build() .also { INSTANCE = it } } } }

package com.example.myapplication.data.store

import android.content.Context
import android.util.Log
import androidx.datastore.preferences.core.edit
import androidx.datastore.preferences.core.stringPreferencesKey
import androidx.datastore.preferences.preferencesDataStore
import com.example.myapplication.BuildConfig
import com.example.myapplication.domain.DateFormatter
import com.example.myapplication.domain.model.PlanResult
import com.example.myapplication.domain.model.WeekPlan
import com.example.myapplication.domain.model.DayPlan
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.flow.callbackFlow
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.tasks.await
import kotlinx.datetime.toLocalDateTime
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaTypeOrNull
import org.json.JSONArray
import org.json.JSONObject
import java.io.IOException
import java.util.concurrent.TimeUnit

import okhttp3.RequestBody.Companion.toRequestBody

// Firebase imports
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import java.util.UUID

val Context.dataStore by preferencesDataStore(name = "plans_datastore")

object PlanDataStore {
    private val PLANS_KEY = stringPreferencesKey("my_plans")
    private val firestore = FirebaseFirestore.getInstance()
    private val auth = FirebaseAuth.getInstance()

    private const val PLANS_COLLECTION = "user_plans"


    // Helper to get resolved ID
    suspend fun getResolvedUserId(): String? {
        if (auth.currentUser == null) return null
        return try {
            FirestoreHelper.getCurrentUserDocRef().id
        } catch (e: Exception) {
            auth.currentUser?.uid // Fallback
        }
    }

    // Dodaj znotraj object PlanDataStore
    suspend fun migrateLocalPlansToFirestore(context: Context) {
        val userId = getResolvedUserId() ?: return
        try {
            // preberi lokalne plane
            val localPlans = loadLocalPlansAndSend(context)
            if (localPlans.isEmpty()) return

            // preveri, če user že ima plane v Firestore
            val snapshot = firestore.collection(PLANS_COLLECTION)
                .document(userId)
                .get()
                .await()

            if (!snapshot.exists()) {
                // migriraj lokalne -> Firestore
                savePlans(context, localPlans)
                Log.d("PlanDataStore", "Migrated ${localPlans.size} local plans to Firestore ($userId)")
            } else {
                Log.d("PlanDataStore", "User already has plans in Firestore, skipping migration")
            }
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error migrating local plans: ${e.message}")
        }
    }

    suspend fun deleteAllPlans() {
        val userId = getResolvedUserId() ?: return
        try {
            // Check if user has plans in Firestore
            val docRef = firestore.collection(PLANS_COLLECTION).document(userId)
            val snapshot = docRef.get().await()

            if (snapshot.exists()) {
                 docRef.delete().await()
                 Log.d("PlanDataStore", "Deleted all plans for user: $userId")
            }
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error deleting all plans: ${e.message}")
            throw e
        }
    }

    fun plansFlow(): Flow<List<PlanResult>> = callbackFlow {
        // Resolve ID async inside the flow
        val userId = try {
            if (auth.currentUser != null) FirestoreHelper.getCurrentUserDocRef().id else null
        } catch (e: Exception) {
            auth.currentUser?.uid
        }

        Log.d("PlanDataStore", "plansFlow called with resolved userId: $userId")

        if (userId == null) {
            Log.e("PlanDataStore", "User not logged in - returning empty list")
            trySend(emptyList())
            close()
            return@callbackFlow
        }

        val listener = firestore.collection(PLANS_COLLECTION)
            .document(userId)
            .addSnapshotListener { snapshot, error ->
                if (error != null) {
                    Log.e("PlanDataStore", "Error listening to plans: ${error.message}")
                    trySend(emptyList()); return@addSnapshotListener
                }

                if (snapshot != null && snapshot.exists()) {
                    @Suppress("UNCHECKED_CAST")
                    val plansData = snapshot.get("plans") as? List<Map<String, Any>>
                    val plans = plansData?.mapNotNull { convertMapToPlanResult(it) } ?: emptyList()
                    trySend(plans)
                } else {
                    trySend(emptyList())
                }
            }

        awaitClose { listener.remove() }
    }

    private suspend fun loadLocalPlansAndSend(context: Context): List<PlanResult> {
        return try {
            val prefs = context.dataStore.data.first()
            val json = prefs[PLANS_KEY] ?: "[]"
            val type = object : TypeToken<List<PlanResult>>() {}.type
            Gson().fromJson<List<PlanResult>>(json, type) ?: emptyList()
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Failed to load local plans: ${e.message}")
            emptyList()
        }
    }

    suspend fun savePlans(context: Context, plans: List<PlanResult>) {
        val userId = getResolvedUserId()

        // Always save locally first as backup/cache
        saveToLocalDataStore(context, plans)

        if (userId == null) {
            Log.e("PlanDataStore", "Cannot save plans to Firestore: User not logged in")
            return
        }

        try {
            val plansData = plans.map { plan ->
                val planMap = hashMapOf<String, Any>(
                    "id" to plan.id,
                    "name" to plan.name,
                    "calories" to plan.calories,
                    "protein" to plan.protein,
                    "carbs" to plan.carbs,
                    "fat" to plan.fat,
                    "trainingPlan" to plan.trainingPlan,
                    "trainingDays" to plan.trainingDays,
                    "sessionLength" to plan.sessionLength,
                    "tips" to plan.tips,
                    "createdAt" to plan.createdAt,
                    "trainingLocation" to plan.trainingLocation,
                    "experience" to (plan.experience ?: ""),
                    "goal" to (plan.goal ?: ""),
                    "startDate" to plan.startDate,
                    "weeks" to plan.weeks.map { week ->
                        hashMapOf<String, Any>(
                            "weekNumber" to week.weekNumber,
                            "days" to week.days.map { day ->
                                hashMapOf<String, Any>(
                                    "dayNumber" to day.dayNumber,
                                    "exercises" to day.exercises,
                                    "isRestDay" to day.isRestDay,
                                    "focusLabel" to day.focusLabel
                                )
                            }
                        )
                    },
                    "focusAreas" to plan.focusAreas,
                    "equipment" to plan.equipment
                )
                plan.algorithmData?.let { algo ->
                    planMap["algorithmData"] = hashMapOf<String, Any>(
                        "bmi" to (algo.bmi ?: 0.0),
                        "bmr" to (algo.bmr ?: 0.0),
                        "tdee" to (algo.tdee ?: 0.0),
                        "proteinPerKg" to (algo.proteinPerKg ?: 0.0),
                        "caloriesPerKg" to (algo.caloriesPerKg ?: 0.0),
                        "caloricStrategy" to (algo.caloricStrategy ?: ""),
                        "detailedTips" to (algo.detailedTips ?: emptyList<String>()),
                        "macroBreakdown" to (algo.macroBreakdown ?: ""),
                        "trainingStrategy" to (algo.trainingStrategy ?: "")
                    )
                }
                planMap
            }

            firestore.collection(PLANS_COLLECTION)
                .document(userId)
                .set(hashMapOf("plans" to plansData))
                .await()

            Log.d("PlanDataStore", "Plans saved successfully to Firestore")
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error saving plans to Firestore: ${e.message}")
        }
    }

    suspend fun addPlan(context: Context, newPlan: PlanResult) {
        val userId = getResolvedUserId()
        if (userId == null) {
            val localPlans = loadLocalPlansAndSend(context).toMutableList()
            localPlans.add(newPlan)
            saveToLocalDataStore(context, localPlans)
            return
        }

        try {
            val currentPlansSnapshot = firestore.collection(PLANS_COLLECTION)
                .document(userId)
                .get()
                .await()

            @Suppress("UNCHECKED_CAST")
            val currentPlansData = if (currentPlansSnapshot.exists()) {
                currentPlansSnapshot.get("plans") as? List<Map<String, Any>> ?: emptyList()
            } else emptyList()

            val currentPlans = currentPlansData.mapNotNull { convertMapToPlanResult(it) }.toMutableList()
            currentPlans.add(newPlan)
            savePlans(context, currentPlans)
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error adding plan to Firestore: ${e.message}")
            val localPlans = loadLocalPlansAndSend(context).toMutableList()
            localPlans.add(newPlan)
            saveToLocalDataStore(context, localPlans)
        }
    }

    /** Posodobi obstoječ plan po ID — brez da klicatelj pozna serializacijo. */
    suspend fun updatePlan(context: Context, updatedPlan: PlanResult) {
        val userId = getResolvedUserId() ?: return
        try {
            val snap = firestore.collection(PLANS_COLLECTION).document(userId).get().await()
            @Suppress("UNCHECKED_CAST")
            val currentPlans = (snap.get("plans") as? List<Map<String, Any>>)
                ?.mapNotNull { convertMapToPlanResult(it) }
                ?.toMutableList() ?: mutableListOf()
            val idx = currentPlans.indexOfFirst { it.id == updatedPlan.id }
            if (idx >= 0) currentPlans[idx] = updatedPlan else currentPlans.add(updatedPlan)
            savePlans(context, currentPlans)
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error updating plan: ${e.message}")
        }
    }

    suspend fun deletePlan(context: Context, planId: String) {
        val userId = getResolvedUserId()
        if (userId == null) {
            val localPlans = loadLocalPlansAndSend(context).filter { it.id != planId }
            saveToLocalDataStore(context, localPlans)
            return
        }

        try {
            val currentPlansSnapshot = firestore.collection(PLANS_COLLECTION)
                .document(userId)
                .get()
                .await()

            @Suppress("UNCHECKED_CAST")
            val currentPlansData = if (currentPlansSnapshot.exists()) {
                currentPlansSnapshot.get("plans") as? List<Map<String, Any>> ?: emptyList()
            } else emptyList()

            val updatedPlans = currentPlansData
                .mapNotNull { convertMapToPlanResult(it) }
                .filter { it.id != planId }

            savePlans(context, updatedPlans)
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error deleting plan from Firestore: ${e.message}")
            val localPlans = loadLocalPlansAndSend(context).filter { it.id != planId }
            saveToLocalDataStore(context, localPlans)
        }
    }

    suspend fun clearPlan(context: Context) {
        // Clear local DataStore
        context.dataStore.edit { prefs ->
            prefs.remove(PLANS_KEY)
        }

        // Clear Firestore active plan
        try {
            val userRef = FirestoreHelper.getCurrentUserDocRef()
            userRef.collection("activePlan").document("current")
                .delete()
                .await()
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Failed to delete active plan: ${e.message}")
        }
    }

    @Suppress("UNCHECKED_CAST")
    private fun convertMapToPlanResult(planMap: Map<String, Any>): PlanResult? {
        return try {
            val weeks = (planMap["weeks"] as? List<Map<String, Any>>)?.map { weekMap ->
                val weekNumber = (weekMap["weekNumber"] as? Number)?.toInt() ?: 1
                val days = (weekMap["days"] as? List<Map<String, Any>>)?.map { dayMap ->
                    val dayNumber = (dayMap["dayNumber"] as? Number)?.toInt() ?: 1
                    val exercises = dayMap["exercises"] as? List<String> ?: emptyList()
                    val isRestDay = dayMap["isRestDay"] as? Boolean ?: false
                    val focusLabel = dayMap["focusLabel"] as? String ?: ""
                    DayPlan(dayNumber, exercises, isRestDay, focusLabel)
                } ?: emptyList()
                WeekPlan(weekNumber, days)
            } ?: emptyList()

            PlanResult(
                id = planMap["id"] as? String ?: "",
                name = planMap["name"] as? String ?: "",
                calories = (planMap["calories"] as? Number)?.toInt() ?: 0,
                protein = (planMap["protein"] as? Number)?.toInt() ?: 0,
                carbs = (planMap["carbs"] as? Number)?.toInt() ?: 0,
                fat = (planMap["fat"] as? Number)?.toInt() ?: 0,
                trainingPlan = planMap["trainingPlan"] as? String ?: "",
                trainingDays = (planMap["trainingDays"] as? Number)?.toInt()?.takeIf { it > 0 } ?: 3,
                sessionLength = (planMap["sessionLength"] as? Number)?.toInt() ?: 0,
                tips = planMap["tips"] as? List<String> ?: emptyList(),
                createdAt = (planMap["createdAt"] as? Number)?.toLong() ?: 0L,
                trainingLocation = planMap["trainingLocation"] as? String ?: "",
                experience = planMap["experience"] as? String,
                goal = planMap["goal"] as? String,
                weeks = weeks,
                startDate = planMap["startDate"] as? String ?: DateFormatter.format(
                    Clock.System.now().toLocalDateTime(
                        TimeZone.currentSystemDefault()).date, "yyyy-MM-dd"),
                focusAreas = when (val fa = planMap["focusAreas"]) {
                    is List<*> -> fa.filterIsInstance<String>()
                    is String -> if (fa.isBlank()) emptyList() else fa.split(",").map { it.trim() }
                    else -> emptyList()
                },
                equipment = when (val eq = planMap["equipment"]) {
                    is List<*> -> eq.filterIsInstance<String>()
                    is String -> if (eq.isBlank()) emptyList() else eq.split(",").map { it.trim() }
                    else -> emptyList()
                },
                algorithmData = (planMap["algorithmData"] as? Map<String, Any>)?.let { algoMap ->
                    AlgorithmData(
                        bmi = (algoMap["bmi"] as? Number)?.toDouble() ?: 0.0,
                        bmr = (algoMap["bmr"] as? Number)?.toDouble() ?: 0.0,
                        tdee = (algoMap["tdee"] as? Number)?.toDouble() ?: 0.0,
                        proteinPerKg = (algoMap["proteinPerKg"] as? Number)?.toDouble() ?: 0.0,
                        caloriesPerKg = (algoMap["caloriesPerKg"] as? Number)?.toDouble() ?: 0.0,
                        caloricStrategy = algoMap["caloricStrategy"] as? String ?: "",
                        detailedTips = algoMap["detailedTips"] as? List<String> ?: emptyList(),
                        macroBreakdown = algoMap["macroBreakdown"] as? String ?: "",
                        trainingStrategy = algoMap["trainingStrategy"] as? String ?: ""
                    )
                }
            )
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error converting plan map: ${e.message}")
            null
        }
    }

    private suspend fun saveToLocalDataStore(context: Context, plans: List<PlanResult>) {
        try {
            val json = Gson().toJson(plans)
            context.dataStore.edit { prefs -> prefs[PLANS_KEY] = json }
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error saving to local datastore: ${e.message}")
        }
    }

    /**
     * Faza 30.4 — Atomarna zamenjava CELOTNIH objektov dni z Firestore transakcijo.
     *
     * Preprečuje:
     *   - Delno kopiranje polj (stara napaka: samo isRestDay + focusLabel)
     *   - Slepo prepisovanje z .set() / .update() (race condition)
     *
     * Potek transakcije (atomarno):
     *   1. Prebere SVEŽO stanje načrta neposredno s strežnika
     *   2. Preveri isFrozen na dayA in dayB (zadnja linija obrambe)
     *   3. Polna zamenjava objektov: dayA ← contentOfB, dayB ← contentOfA
     *      Ohrani le dayNumber (pozicijski indeks) — vse ostalo je zamenjano
     *   4. transaction.update() samo za `plans` polje — ne prepiše celotnega dokumenta
     *
     * Klic chain: PlanRepositoryImpl → tu (ne neposredno iz ViewModel/UseCase).
     */
    suspend fun swapDaysAtomically(planId: String, dayA: Int, dayB: Int): Result<Unit> {
        if (planId.isBlank()) {
            return Result.failure(Exception("Plan ID is empty — cannot execute atomic swap."))
        }
        val userId = getResolvedUserId()
            ?: return Result.failure(Exception("User not logged in — cannot swap."))

        return try {
            firestore.runTransaction { transaction ->
                val docRef = firestore.collection(PLANS_COLLECTION).document(userId)
                val snapshot = transaction.get(docRef)

                @Suppress("UNCHECKED_CAST")
                val plansData = snapshot.get("plans") as? List<Map<String, Any>>
                    ?: throw Exception("No plans found in Firestore document.")

                // Najdi pravi plan po planId
                val planIndex = plansData.indexOfFirst { it["id"] == planId }
                if (planIndex < 0) throw Exception("Plan $planId not found in Firestore.")

                val planMap = plansData[planIndex]
                @Suppress("UNCHECKED_CAST")
                val weeks = planMap["weeks"] as? List<Map<String, Any>>
                    ?: throw Exception("No weeks data in plan $planId.")

                //  Faza 30.3/30.4 — Preveri isFrozen NEPOSREDNO iz Firestorea (svež read s strežnika)
                weeks.forEach { weekMap ->
                    @Suppress("UNCHECKED_CAST")
                    (weekMap["days"] as? List<Map<String, Any>> ?: emptyList()).forEach { dayMap ->
                        val dayNum = (dayMap["dayNumber"] as? Number)?.toInt()
                        val frozen = dayMap["isFrozen"] as? Boolean ?: false
                        if (frozen && (dayNum == dayA || dayNum == dayB)) {
                            throw Exception("Day $dayNum je zamrznjen v Firestore — swap blokiran.")
                        }
                    }
                }

                // Faza 30.4 — Zberi CELOTNA objekta dni (ne samo posamezna polja)
                var fullDayMapA: Map<String, Any>? = null
                var fullDayMapB: Map<String, Any>? = null
                weeks.forEach { weekMap ->
                    @Suppress("UNCHECKED_CAST")
                    (weekMap["days"] as? List<Map<String, Any>> ?: emptyList()).forEach { dayMap ->
                        val dayNum = (dayMap["dayNumber"] as? Number)?.toInt()
                        if (dayNum == dayA) fullDayMapA = dayMap
                        if (dayNum == dayB) fullDayMapB = dayMap
                    }
                }
                if (fullDayMapA == null || fullDayMapB == null) {
                    throw Exception("Day not found in plan: dayA=$dayA, dayB=$dayB")
                }

                // Faza 30.5 — Varno razpakiranje brez !! operatorja
                // Elvis ?: throw zagotavlja, da transakcija nikoli ne crasha nepričakovano
                val contentOfA = (fullDayMapA ?: throw Exception("Day $dayA not found — swap aborted."))
                    .toMutableMap().apply { remove("dayNumber") }
                val contentOfB = (fullDayMapB ?: throw Exception("Day $dayB not found — swap aborted."))
                    .toMutableMap().apply { remove("dayNumber") }

                // Polna zamenjava: dayA slot ← vsebina B, dayB slot ← vsebina A
                val updatedWeeks = weeks.map { weekMap ->
                    @Suppress("UNCHECKED_CAST")
                    val updatedDays = (weekMap["days"] as? List<Map<String, Any>> ?: emptyList())
                        .map { dayMap ->
                            val dayNum = (dayMap["dayNumber"] as? Number)?.toInt()
                            when (dayNum) {
                                dayA -> contentOfB.toMutableMap().apply { put("dayNumber", dayA) }
                                dayB -> contentOfA.toMutableMap().apply { put("dayNumber", dayB) }
                                else -> dayMap
                            }
                        }
                    weekMap.toMutableMap().apply { put("days", updatedDays) }
                }

                // transaction.update() — samo `plans` polje, ne prepiše celotnega dokumenta
                val updatedPlansData = plansData.toMutableList()
                updatedPlansData[planIndex] = planMap.toMutableMap().apply {
                    put("weeks", updatedWeeks)
                }
                transaction.update(docRef, "plans", updatedPlansData)

            }.await()

            Log.d("PlanDataStore", "✅ Atomarni swap uspel: dan $dayA ↔ dan $dayB (plan=$planId)")
            Result.success(Unit)
        } catch (e: Exception) {
            Log.e("PlanDataStore", "❌ Atomarni swap spodletel: ${e.message}")
            Result.failure(e)
        }
    }

    // KLJUČNO: klic na Cloud Run z Authorization headerjem
    fun requestAIPlan(
        quizData: Map<String, Any>,
        onResult: (PlanResult) -> Unit,
        onError: (String?) -> Unit
    ) {
        val baseUrl = BuildConfig.FITNESS_API_BASE_URL.ifBlank {
            "https://fitness-plan-api-551351477998.europe-west1.run.app"
        }
        val url = "${baseUrl.trimEnd('/')}/generate-plan"

        try {
            val currentUser = auth.currentUser
            val userId = currentUser?.uid
            val userEmail = currentUser?.email

            if (userId == null) {
                onError("User not logged in"); return
            }

            val json = JSONObject().apply {
                put("user_data", JSONObject().apply {
                    put("user_id", userId)
                    put("user_email", userEmail ?: "")
                    put("gender", quizData["gender"] ?: "")
                    put("age", quizData["age"] ?: "")
                    put("height", quizData["height"] ?: "")
                    put("weight", quizData["weight"] ?: "")
                    put("goal", quizData["goal"] ?: "")
                    put("experience", quizData["experience"] ?: "")
                    put("training_location", quizData["training_location"] ?: "")
                    put("trainingDays", quizData["trainingDays"] ?: 3)
                    put("limitations", JSONArray(quizData["limitations"] as? List<*> ?: emptyList<String>()))
                    put("nutrition", quizData["nutrition"] ?: "")
                    put("sleep", quizData["sleep"] ?: "")
                })
                put("timestamp", System.currentTimeMillis())
            }

            val body = json.toString().toRequestBody("application/json; charset=utf-8".toMediaTypeOrNull())

            val request = Request.Builder()
                .url(url)
                .post(body)
                .addHeader("Content-Type", "application/json")
                .addHeader("Accept", "application/json")
                .addHeader("Authorization", "Bearer ${BuildConfig.BACKEND_API_KEY}")
                .build()

            val client = OkHttpClient.Builder()
                .connectTimeout(60, TimeUnit.SECONDS)
                .writeTimeout(60, TimeUnit.SECONDS)
                .readTimeout(180, TimeUnit.SECONDS)
                .callTimeout(240, TimeUnit.SECONDS)
                .build()

            client.newCall(request).enqueue(object : Callback {
                override fun onFailure(call: Call, e: IOException) {
                    Log.e("PlanDataStore", "AI request failed: ${e.message}")
                    if (e.message?.contains("timeout", ignoreCase = true) == true) {
                        onError("AI is taking longer than expected. Please try again or use the local plan.")
                    } else {
                        onError("Connection error: ${e.localizedMessage}")
                    }
                }

                override fun onResponse(call: Call, response: Response) {
                    val responseBody = response.body?.string()
                    if (!response.isSuccessful) {
                        onError("Server error ${response.code}: $responseBody"); return
                    }

                    val planObj = try {
                        val jsonObject = JSONObject(responseBody ?: "{}")
                        val weeks = if (jsonObject.has("weeks")) {
                            parseWeeksFromJson(jsonObject.getJSONArray("weeks"))
                        } else emptyList()

                        PlanResult(
                            id = UUID.randomUUID().toString(),
                            name = jsonObject.optString("name", "AI Plan"),
                            calories = jsonObject.optInt("calories", 2000),
                            protein = jsonObject.optInt("protein", 150),
                            carbs = jsonObject.optInt("carbs", 200),
                            fat = jsonObject.optInt("fat", 50),
                            trainingPlan = jsonObject.optString(
                                "suggestedWorkout",
                                jsonObject.optString("trainingPlan", "Default training plan")
                            ),
                            trainingDays = jsonObject.optInt("trainingDays", 3),
                            sessionLength = jsonObject.optInt("sessionLength", 60),
                            tips = parseStringArray(jsonObject.optJSONArray("tips")),
                            createdAt = System.currentTimeMillis(),
                            trainingLocation = quizData["training_location"] as? String ?: "Home",
                            experience = jsonObject.optString("experience").takeIf { it.isNotEmpty() },
                            goal = jsonObject.optString("goal").takeIf { it.isNotEmpty() },
                            weeks = weeks,
                            algorithmData = null
                        )
                    } catch (e: Exception) {
                        Log.e("PlanDataStore", "Error parsing AI response: ${e.message}")
                        null
                    }

                    if (planObj != null) onResult(planObj) else onError("Failed to parse AI response")
                }
            })
        } catch (e: Exception) {
            Log.e("PlanDataStore", "AI request setup failed: ${e.message}")
            onError("Request setup error: ${e.localizedMessage}")
        }
    }

    private fun parseStringArray(jsonArray: JSONArray?): List<String> {
        if (jsonArray == null) return emptyList()
        return buildList {
            for (i in 0 until jsonArray.length()) add(jsonArray.getString(i))
        }
    }

    fun parseWeeksFromJson(weeksJson: JSONArray): List<WeekPlan> {
        val weeks = mutableListOf<WeekPlan>()
        for (i in 0 until weeksJson.length()) {
            val weekObj = weeksJson.getJSONObject(i)
            val weekNumber = weekObj.getInt("weekNumber")
            val daysJson = weekObj.getJSONArray("days")
            val days = mutableListOf<DayPlan>()
            for (j in 0 until daysJson.length()) {
                val dayObj = daysJson.getJSONObject(j)
                val dayNumber = dayObj.getInt("dayNumber")
                val exercisesJson = dayObj.optJSONArray("exercises") ?: JSONArray()
                val exercises = mutableListOf<String>()
                for (k in 0 until exercisesJson.length()) {
                    exercises.add(exercisesJson.getString(k))
                }
                val isRestDay = dayObj.optBoolean("isRestDay", false)
                val focusLabel = dayObj.optString("focusLabel", "")
                days.add(DayPlan(dayNumber, exercises, isRestDay, focusLabel))
            }
            weeks.add(WeekPlan(weekNumber, days))
        }
        return weeks
    }
}

package com.example.myapplication.data.store

import android.content.Context
import android.util.Log
import androidx.datastore.preferences.core.edit
import androidx.datastore.preferences.core.stringPreferencesKey
import androidx.datastore.preferences.preferencesDataStore
import com.example.myapplication.BuildConfig
import com.example.myapplication.domain.DateFormatter
import com.example.myapplication.domain.model.PlanResult
import com.example.myapplication.domain.model.WeekPlan
import com.example.myapplication.domain.model.DayPlan
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.flow.callbackFlow
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.tasks.await
import kotlinx.datetime.toLocalDateTime
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaTypeOrNull
import org.json.JSONArray
import org.json.JSONObject
import java.io.IOException
import java.util.concurrent.TimeUnit

import okhttp3.RequestBody.Companion.toRequestBody

// Firebase imports
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import java.util.UUID

val Context.dataStore by preferencesDataStore(name = "plans_datastore")

object PlanDataStore {
    private val PLANS_KEY = stringPreferencesKey("my_plans")
    private val firestore = FirebaseFirestore.getInstance()
    private val auth = FirebaseAuth.getInstance()

    private const val PLANS_COLLECTION = "user_plans"


    // Helper to get resolved ID
    suspend fun getResolvedUserId(): String? {
        if (auth.currentUser == null) return null
        return try {
            FirestoreHelper.getCurrentUserDocRef().id
        } catch (e: Exception) {
            auth.currentUser?.uid // Fallback
        }
    }

    // Dodaj znotraj object PlanDataStore
    suspend fun migrateLocalPlansToFirestore(context: Context) {
        val userId = getResolvedUserId() ?: return
        try {
            // preberi lokalne plane
            val localPlans = loadLocalPlansAndSend(context)
            if (localPlans.isEmpty()) return

            // preveri, če user že ima plane v Firestore
            val snapshot = firestore.collection(PLANS_COLLECTION)
                .document(userId)
                .get()
                .await()

            if (!snapshot.exists()) {
                // migriraj lokalne -> Firestore
                savePlans(context, localPlans)
                Log.d("PlanDataStore", "Migrated ${localPlans.size} local plans to Firestore ($userId)")
            } else {
                Log.d("PlanDataStore", "User already has plans in Firestore, skipping migration")
            }
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error migrating local plans: ${e.message}")
        }
    }

    suspend fun deleteAllPlans() {
        val userId = getResolvedUserId() ?: return
        try {
            // Check if user has plans in Firestore
            val docRef = firestore.collection(PLANS_COLLECTION).document(userId)
            val snapshot = docRef.get().await()

            if (snapshot.exists()) {
                 docRef.delete().await()
                 Log.d("PlanDataStore", "Deleted all plans for user: $userId")
            }
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error deleting all plans: ${e.message}")
            throw e
        }
    }

    fun plansFlow(): Flow<List<PlanResult>> = callbackFlow {
        // Resolve ID async inside the flow
        val userId = try {
            if (auth.currentUser != null) FirestoreHelper.getCurrentUserDocRef().id else null
        } catch (e: Exception) {
            auth.currentUser?.uid
        }

        Log.d("PlanDataStore", "plansFlow called with resolved userId: $userId")

        if (userId == null) {
            Log.e("PlanDataStore", "User not logged in - returning empty list")
            trySend(emptyList())
            close()
            return@callbackFlow
        }

        val listener = firestore.collection(PLANS_COLLECTION)
            .document(userId)
            .addSnapshotListener { snapshot, error ->
                if (error != null) {
                    Log.e("PlanDataStore", "Error listening to plans: ${error.message}")
                    trySend(emptyList()); return@addSnapshotListener
                }

                if (snapshot != null && snapshot.exists()) {
                    @Suppress("UNCHECKED_CAST")
                    val plansData = snapshot.get("plans") as? List<Map<String, Any>>
                    val plans = plansData?.mapNotNull { convertMapToPlanResult(it) } ?: emptyList()
                    trySend(plans)
                } else {
                    trySend(emptyList())
                }
            }

        awaitClose { listener.remove() }
    }

    private suspend fun loadLocalPlansAndSend(context: Context): List<PlanResult> {
        return try {
            val prefs = context.dataStore.data.first()
            val json = prefs[PLANS_KEY] ?: "[]"
            val type = object : TypeToken<List<PlanResult>>() {}.type
            Gson().fromJson<List<PlanResult>>(json, type) ?: emptyList()
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Failed to load local plans: ${e.message}")
            emptyList()
        }
    }

    suspend fun savePlans(context: Context, plans: List<PlanResult>) {
        val userId = getResolvedUserId()

        // Always save locally first as backup/cache
        saveToLocalDataStore(context, plans)

        if (userId == null) {
            Log.e("PlanDataStore", "Cannot save plans to Firestore: User not logged in")
            return
        }

        try {
            val plansData = plans.map { plan ->
                val planMap = hashMapOf<String, Any>(
                    "id" to plan.id,
                    "name" to plan.name,
                    "calories" to plan.calories,
                    "protein" to plan.protein,
                    "carbs" to plan.carbs,
                    "fat" to plan.fat,
                    "trainingPlan" to plan.trainingPlan,
                    "trainingDays" to plan.trainingDays,
                    "sessionLength" to plan.sessionLength,
                    "tips" to plan.tips,
                    "createdAt" to plan.createdAt,
                    "trainingLocation" to plan.trainingLocation,
                    "experience" to (plan.experience ?: ""),
                    "goal" to (plan.goal ?: ""),
                    "startDate" to plan.startDate,
                    "weeks" to plan.weeks.map { week ->
                        hashMapOf<String, Any>(
                            "weekNumber" to week.weekNumber,
                            "days" to week.days.map { day ->
                                hashMapOf<String, Any>(
                                    "dayNumber" to day.dayNumber,
                                    "exercises" to day.exercises,
                                    "isRestDay" to day.isRestDay,
                                    "focusLabel" to day.focusLabel
                                )
                            }
                        )
                    },
                    "focusAreas" to plan.focusAreas,
                    "equipment" to plan.equipment
                )
                plan.algorithmData?.let { algo ->
                    planMap["algorithmData"] = hashMapOf<String, Any>(
                        "bmi" to (algo.bmi ?: 0.0),
                        "bmr" to (algo.bmr ?: 0.0),
                        "tdee" to (algo.tdee ?: 0.0),
                        "proteinPerKg" to (algo.proteinPerKg ?: 0.0),
                        "caloriesPerKg" to (algo.caloriesPerKg ?: 0.0),
                        "caloricStrategy" to (algo.caloricStrategy ?: ""),
                        "detailedTips" to (algo.detailedTips ?: emptyList<String>()),
                        "macroBreakdown" to (algo.macroBreakdown ?: ""),
                        "trainingStrategy" to (algo.trainingStrategy ?: "")
                    )
                }
                planMap
            }

            firestore.collection(PLANS_COLLECTION)
                .document(userId)
                .set(hashMapOf("plans" to plansData))
                .await()

            Log.d("PlanDataStore", "Plans saved successfully to Firestore")
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error saving plans to Firestore: ${e.message}")
        }
    }

    suspend fun addPlan(context: Context, newPlan: PlanResult) {
        val userId = getResolvedUserId()
        if (userId == null) {
            val localPlans = loadLocalPlansAndSend(context).toMutableList()
            localPlans.add(newPlan)
            saveToLocalDataStore(context, localPlans)
            return
        }

        try {
            val currentPlansSnapshot = firestore.collection(PLANS_COLLECTION)
                .document(userId)
                .get()
                .await()

            @Suppress("UNCHECKED_CAST")
            val currentPlansData = if (currentPlansSnapshot.exists()) {
                currentPlansSnapshot.get("plans") as? List<Map<String, Any>> ?: emptyList()
            } else emptyList()

            val currentPlans = currentPlansData.mapNotNull { convertMapToPlanResult(it) }.toMutableList()
            currentPlans.add(newPlan)
            savePlans(context, currentPlans)
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error adding plan to Firestore: ${e.message}")
            val localPlans = loadLocalPlansAndSend(context).toMutableList()
            localPlans.add(newPlan)
            saveToLocalDataStore(context, localPlans)
        }
    }

    /** Posodobi obstoječ plan po ID — brez da klicatelj pozna serializacijo. */
    suspend fun updatePlan(context: Context, updatedPlan: PlanResult) {
        val userId = getResolvedUserId() ?: return
        try {
            val snap = firestore.collection(PLANS_COLLECTION).document(userId).get().await()
            @Suppress("UNCHECKED_CAST")
            val currentPlans = (snap.get("plans") as? List<Map<String, Any>>)
                ?.mapNotNull { convertMapToPlanResult(it) }
                ?.toMutableList() ?: mutableListOf()
            val idx = currentPlans.indexOfFirst { it.id == updatedPlan.id }
            if (idx >= 0) currentPlans[idx] = updatedPlan else currentPlans.add(updatedPlan)
            savePlans(context, currentPlans)
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error updating plan: ${e.message}")
        }
    }

    suspend fun deletePlan(context: Context, planId: String) {
        val userId = getResolvedUserId()
        if (userId == null) {
            val localPlans = loadLocalPlansAndSend(context).filter { it.id != planId }
            saveToLocalDataStore(context, localPlans)
            return
        }

        try {
            val currentPlansSnapshot = firestore.collection(PLANS_COLLECTION)
                .document(userId)
                .get()
                .await()

            @Suppress("UNCHECKED_CAST")
            val currentPlansData = if (currentPlansSnapshot.exists()) {
                currentPlansSnapshot.get("plans") as? List<Map<String, Any>> ?: emptyList()
            } else emptyList()

            val updatedPlans = currentPlansData
                .mapNotNull { convertMapToPlanResult(it) }
                .filter { it.id != planId }

            savePlans(context, updatedPlans)
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error deleting plan from Firestore: ${e.message}")
            val localPlans = loadLocalPlansAndSend(context).filter { it.id != planId }
            saveToLocalDataStore(context, localPlans)
        }
    }

    suspend fun clearPlan(context: Context) {
        // Clear local DataStore
        context.dataStore.edit { prefs ->
            prefs.remove(PLANS_KEY)
        }

        // Clear Firestore active plan
        try {
            val userRef = FirestoreHelper.getCurrentUserDocRef()
            userRef.collection("activePlan").document("current")
                .delete()
                .await()
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Failed to delete active plan: ${e.message}")
        }
    }

    @Suppress("UNCHECKED_CAST")
    private fun convertMapToPlanResult(planMap: Map<String, Any>): PlanResult? {
        return try {
            val weeks = (planMap["weeks"] as? List<Map<String, Any>>)?.map { weekMap ->
                val weekNumber = (weekMap["weekNumber"] as? Number)?.toInt() ?: 1
                val days = (weekMap["days"] as? List<Map<String, Any>>)?.map { dayMap ->
                    val dayNumber = (dayMap["dayNumber"] as? Number)?.toInt() ?: 1
                    val exercises = dayMap["exercises"] as? List<String> ?: emptyList()
                    val isRestDay = dayMap["isRestDay"] as? Boolean ?: false
                    val focusLabel = dayMap["focusLabel"] as? String ?: ""
                    DayPlan(dayNumber, exercises, isRestDay, focusLabel)
                } ?: emptyList()
                WeekPlan(weekNumber, days)
            } ?: emptyList()

            PlanResult(
                id = planMap["id"] as? String ?: "",
                name = planMap["name"] as? String ?: "",
                calories = (planMap["calories"] as? Number)?.toInt() ?: 0,
                protein = (planMap["protein"] as? Number)?.toInt() ?: 0,
                carbs = (planMap["carbs"] as? Number)?.toInt() ?: 0,
                fat = (planMap["fat"] as? Number)?.toInt() ?: 0,
                trainingPlan = planMap["trainingPlan"] as? String ?: "",
                trainingDays = (planMap["trainingDays"] as? Number)?.toInt()?.takeIf { it > 0 } ?: 3,
                sessionLength = (planMap["sessionLength"] as? Number)?.toInt() ?: 0,
                tips = planMap["tips"] as? List<String> ?: emptyList(),
                createdAt = (planMap["createdAt"] as? Number)?.toLong() ?: 0L,
                trainingLocation = planMap["trainingLocation"] as? String ?: "",
                experience = planMap["experience"] as? String,
                goal = planMap["goal"] as? String,
                weeks = weeks,
                startDate = planMap["startDate"] as? String ?: DateFormatter.format(
                    Clock.System.now().toLocalDateTime(
                        TimeZone.currentSystemDefault()).date, "yyyy-MM-dd"),
                focusAreas = when (val fa = planMap["focusAreas"]) {
                    is List<*> -> fa.filterIsInstance<String>()
                    is String -> if (fa.isBlank()) emptyList() else fa.split(",").map { it.trim() }
                    else -> emptyList()
                },
                equipment = when (val eq = planMap["equipment"]) {
                    is List<*> -> eq.filterIsInstance<String>()
                    is String -> if (eq.isBlank()) emptyList() else eq.split(",").map { it.trim() }
                    else -> emptyList()
                },
                algorithmData = (planMap["algorithmData"] as? Map<String, Any>)?.let { algoMap ->
                    AlgorithmData(
                        bmi = (algoMap["bmi"] as? Number)?.toDouble() ?: 0.0,
                        bmr = (algoMap["bmr"] as? Number)?.toDouble() ?: 0.0,
                        tdee = (algoMap["tdee"] as? Number)?.toDouble() ?: 0.0,
                        proteinPerKg = (algoMap["proteinPerKg"] as? Number)?.toDouble() ?: 0.0,
                        caloriesPerKg = (algoMap["caloriesPerKg"] as? Number)?.toDouble() ?: 0.0,
                        caloricStrategy = algoMap["caloricStrategy"] as? String ?: "",
                        detailedTips = algoMap["detailedTips"] as? List<String> ?: emptyList(),
                        macroBreakdown = algoMap["macroBreakdown"] as? String ?: "",
                        trainingStrategy = algoMap["trainingStrategy"] as? String ?: ""
                    )
                }
            )
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error converting plan map: ${e.message}")
            null
        }
    }

    private suspend fun saveToLocalDataStore(context: Context, plans: List<PlanResult>) {
        try {
            val json = Gson().toJson(plans)
            context.dataStore.edit { prefs -> prefs[PLANS_KEY] = json }
        } catch (e: Exception) {
            Log.e("PlanDataStore", "Error saving to local datastore: ${e.message}")
        }
    }

    /**
     * Faza 30.4 — Atomarna zamenjava CELOTNIH objektov dni z Firestore transakcijo.
     *
     * Preprečuje:
     *   - Delno kopiranje polj (stara napaka: samo isRestDay + focusLabel)
     *   - Slepo prepisovanje z .set() / .update() (race condition)
     *
     * Potek transakcije (atomarno):
     *   1. Prebere SVEŽO stanje načrta neposredno s strežnika
     *   2. Preveri isFrozen na dayA in dayB (zadnja linija obrambe)
     *   3. Polna zamenjava objektov: dayA ← contentOfB, dayB ← contentOfA
     *      Ohrani le dayNumber (pozicijski indeks) — vse ostalo je zamenjano
     *   4. transaction.update() samo za `plans` polje — ne prepiše celotnega dokumenta
     *
     * Klic chain: PlanRepositoryImpl → tu (ne neposredno iz ViewModel/UseCase).
     */
    suspend fun swapDaysAtomically(planId: String, dayA: Int, dayB: Int): Result<Unit> {
        if (planId.isBlank()) {
            return Result.failure(Exception("Plan ID is empty — cannot execute atomic swap."))
        }
        val userId = getResolvedUserId()
            ?: return Result.failure(Exception("User not logged in — cannot swap."))

        return try {
            firestore.runTransaction { transaction ->
                val docRef = firestore.collection(PLANS_COLLECTION).document(userId)
                val snapshot = transaction.get(docRef)

                // Faza 31.9 — Popravek #1: Firestore vrne notranji AbstractList (nespremenljiv).
                // Eksplicitna pretvorba v MutableList<MutableMap> prepreči UnsupportedOperationException
                // ob vsakem indexOf / set / put klicu znotraj transakcije.
                @Suppress("UNCHECKED_CAST")
                val plansData: MutableList<MutableMap<String, Any>> =
                    (snapshot.get("plans") as? List<*>)
                        ?.filterIsInstance<Map<String, Any>>()
                        ?.map { it.toMutableMap() }
                        ?.toMutableList()
                        ?: throw Exception("No plans found in Firestore document.")

                // Najdi pravi plan po planId
                val planIndex = plansData.indexOfFirst { it["id"] == planId }
                if (planIndex < 0) throw Exception("Plan $planId not found in Firestore.")

                val planMap: MutableMap<String, Any> = plansData[planIndex]

                // Faza 31.9 — weeks je morda Firestore-ov nespremenljivi seznam → explicitni toMutableList()
                @Suppress("UNCHECKED_CAST")
                val weeks: MutableList<MutableMap<String, Any>> =
                    (planMap["weeks"] as? List<*>)
                        ?.filterIsInstance<Map<String, Any>>()
                        ?.map { it.toMutableMap() }
                        ?.toMutableList()
                        ?: throw Exception("No weeks data in plan $planId.")

                //  Faza 30.3/30.4 — Preveri isFrozen NEPOSREDNO iz Firestorea (svež read s strežnika)
                weeks.forEach { weekMap ->
                    @Suppress("UNCHECKED_CAST")
                    val days = (weekMap["days"] as? List<*>)
                        ?.filterIsInstance<Map<String, Any>>()
                        ?: emptyList()
                    days.forEach { dayMap ->
                        val dayNum = (dayMap["dayNumber"] as? Number)?.toInt()
                        val frozen = dayMap["isFrozen"] as? Boolean ?: false
                        if (frozen && (dayNum == dayA || dayNum == dayB)) {
                            throw Exception("Day $dayNum je zamrznjen v Firestore — swap blokiran.")
                        }
                    }
                }

                // Faza 30.4 — Zberi CELOTNA objekta dni (ne samo posamezna polja)
                var fullDayMapA: Map<String, Any>? = null
                var fullDayMapB: Map<String, Any>? = null
                weeks.forEach { weekMap ->
                    @Suppress("UNCHECKED_CAST")
                    val days = (weekMap["days"] as? List<*>)
                        ?.filterIsInstance<Map<String, Any>>()
                        ?: emptyList()
                    days.forEach { dayMap ->
                        val dayNum = (dayMap["dayNumber"] as? Number)?.toInt()
                        if (dayNum == dayA) fullDayMapA = dayMap
                        if (dayNum == dayB) fullDayMapB = dayMap
                    }
                }
                if (fullDayMapA == null || fullDayMapB == null) {
                    throw Exception("Day not found in plan: dayA=$dayA, dayB=$dayB")
                }

                // Faza 30.5 — Varno razpakiranje brez !! operatorja
                // Faza 31.9 — Globoka kopija: remove("dayNumber") deluje samo na KOPIJI, ne na originalnem
                // Firestore map objektu (ki je morda dodeljen samo po referenci).
                val contentOfA: MutableMap<String, Any> =
                    (fullDayMapA ?: throw Exception("Day $dayA not found — swap aborted."))
                        .toMutableMap().apply { remove("dayNumber") }
                val contentOfB: MutableMap<String, Any> =
                    (fullDayMapB ?: throw Exception("Day $dayB not found — swap aborted."))
                        .toMutableMap().apply { remove("dayNumber") }

                // Polna zamenjava: dayA slot ← vsebina B, dayB slot ← vsebina A
                val updatedWeeks: List<MutableMap<String, Any>> = weeks.map { weekMap ->
                    @Suppress("UNCHECKED_CAST")
                    // Faza 31.9: Eksplicitni toMutableList() na dneh — Firestore List je nespremenljiv
                    val updatedDays: MutableList<MutableMap<String, Any>> =
                        (weekMap["days"] as? List<*>)
                            ?.filterIsInstance<Map<String, Any>>()
                            ?.map { dayMap ->
                                val dayNum = (dayMap["dayNumber"] as? Number)?.toInt()
                                when (dayNum) {
                                    dayA -> (contentOfB.toMutableMap()).apply { put("dayNumber", dayA) }
                                    dayB -> (contentOfA.toMutableMap()).apply { put("dayNumber", dayB) }
                                    // Faza 31.9: else veja — tudi originalni dayMap pretvori v MutableMap,
                                    // da celoten seznam ostane homogeno mutabilen
                                    else -> dayMap.toMutableMap()
                                }
                            }
                            ?.toMutableList()
                            ?: mutableListOf()
                    weekMap.toMutableMap().apply { put("days", updatedDays) }
                }

                // transaction.update() — samo `plans` polje, ne prepiše celotnega dokumenta
                planMap["weeks"] = updatedWeeks
                plansData[planIndex] = planMap
                transaction.update(docRef, "plans", plansData)

            }.await()

            Log.d("PlanDataStore", "✅ Atomarni swap uspel: dan $dayA ↔ dan $dayB (plan=$planId)")
            Result.success(Unit)
        } catch (e: Exception) {
            Log.e("PlanDataStore", "❌ Atomarni swap spodletel: ${e.message}")
            Result.failure(e)
        }
    }

    // KLJUČNO: klic na Cloud Run z Authorization headerjem
    fun requestAIPlan(
        quizData: Map<String, Any>,
        onResult: (PlanResult) -> Unit,
        onError: (String?) -> Unit
    ) {
        val baseUrl = BuildConfig.FITNESS_API_BASE_URL.ifBlank {
            "https://fitness-plan-api-551351477998.europe-west1.run.app"
        }
        val url = "${baseUrl.trimEnd('/')}/generate-plan"

        try {
            val currentUser = auth.currentUser
            val userId = currentUser?.uid
            val userEmail = currentUser?.email

            if (userId == null) {
                onError("User not logged in"); return
            }

            val json = JSONObject().apply {
                put("user_data", JSONObject().apply {
                    put("user_id", userId)
                    put("user_email", userEmail ?: "")
                    put("gender", quizData["gender"] ?: "")
                    put("age", quizData["age"] ?: "")
                    put("height", quizData["height"] ?: "")
                    put("weight", quizData["weight"] ?: "")
                    put("goal", quizData["goal"] ?: "")
                    put("experience", quizData["experience"] ?: "")
                    put("training_location", quizData["training_location"] ?: "")
                    put("trainingDays", quizData["trainingDays"] ?: 3)
                    put("limitations", JSONArray(quizData["limitations"] as? List<*> ?: emptyList<String>()))
                    put("nutrition", quizData["nutrition"] ?: "")
                    put("sleep", quizData["sleep"] ?: "")
                })
                put("timestamp", System.currentTimeMillis())
            }

            val body = json.toString().toRequestBody("application/json; charset=utf-8".toMediaTypeOrNull())

            val request = Request.Builder()
                .url(url)
                .post(body)
                .addHeader("Content-Type", "application/json")
                .addHeader("Accept", "application/json")
                .addHeader("Authorization", "Bearer ${BuildConfig.BACKEND_API_KEY}")
                .build()

            val client = OkHttpClient.Builder()
                .connectTimeout(60, TimeUnit.SECONDS)
                .writeTimeout(60, TimeUnit.SECONDS)
                .readTimeout(180, TimeUnit.SECONDS)
                .callTimeout(240, TimeUnit.SECONDS)
                .build()

            client.newCall(request).enqueue(object : Callback {
                override fun onFailure(call: Call, e: IOException) {
                    Log.e("PlanDataStore", "AI request failed: ${e.message}")
                    if (e.message?.contains("timeout", ignoreCase = true) == true) {
                        onError("AI is taking longer than expected. Please try again or use the local plan.")
                    } else {
                        onError("Connection error: ${e.localizedMessage}")
                    }
                }

                override fun onResponse(call: Call, response: Response) {
                    val responseBody = response.body?.string()
                    if (!response.isSuccessful) {
                        onError("Server error ${response.code}: $responseBody"); return
                    }

                    val planObj = try {
                        val jsonObject = JSONObject(responseBody ?: "{}")
                        val weeks = if (jsonObject.has("weeks")) {
                            parseWeeksFromJson(jsonObject.getJSONArray("weeks"))
                        } else emptyList()

                        PlanResult(
                            id = UUID.randomUUID().toString(),
                            name = jsonObject.optString("name", "AI Plan"),
                            calories = jsonObject.optInt("calories", 2000),
                            protein = jsonObject.optInt("protein", 150),
                            carbs = jsonObject.optInt("carbs", 200),
                            fat = jsonObject.optInt("fat", 50),
                            trainingPlan = jsonObject.optString(
                                "suggestedWorkout",
                                jsonObject.optString("trainingPlan", "Default training plan")
                            ),
                            trainingDays = jsonObject.optInt("trainingDays", 3),
                            sessionLength = jsonObject.optInt("sessionLength", 60),
                            tips = parseStringArray(jsonObject.optJSONArray("tips")),
                            createdAt = System.currentTimeMillis(),
                            trainingLocation = quizData["training_location"] as? String ?: "Home",
                            experience = jsonObject.optString("experience").takeIf { it.isNotEmpty() },
                            goal = jsonObject.optString("goal").takeIf { it.isNotEmpty() },
                            weeks = weeks,
                            algorithmData = null
                        )
                    } catch (e: Exception) {
                        Log.e("PlanDataStore", "Error parsing AI response: ${e.message}")
                        null
                    }

                    if (planObj != null) onResult(planObj) else onError("Failed to parse AI response")
                }
            })
        } catch (e: Exception) {
            Log.e("PlanDataStore", "AI request setup failed: ${e.message}")
            onError("Request setup error: ${e.localizedMessage}")
        }
    }

    private fun parseStringArray(jsonArray: JSONArray?): List<String> {
        if (jsonArray == null) return emptyList()
        return buildList {
            for (i in 0 until jsonArray.length()) add(jsonArray.getString(i))
        }
    }

    fun parseWeeksFromJson(weeksJson: JSONArray): List<WeekPlan> {
        val weeks = mutableListOf<WeekPlan>()
        for (i in 0 until weeksJson.length()) {
            val weekObj = weeksJson.getJSONObject(i)
            val weekNumber = weekObj.getInt("weekNumber")
            val daysJson = weekObj.getJSONArray("days")
            val days = mutableListOf<DayPlan>()
            for (j in 0 until daysJson.length()) {
                val dayObj = daysJson.getJSONObject(j)
                val dayNumber = dayObj.getInt("dayNumber")
                val exercisesJson = dayObj.optJSONArray("exercises") ?: JSONArray()
                val exercises = mutableListOf<String>()
                for (k in 0 until exercisesJson.length()) {
                    exercises.add(exercisesJson.getString(k))
                }
                val isRestDay = dayObj.optBoolean("isRestDay", false)
                val focusLabel = dayObj.optString("focusLabel", "")
                days.add(DayPlan(dayNumber, exercises, isRestDay, focusLabel))
            }
            weeks.add(WeekPlan(weekNumber, days))
        }
        return weeks
    }
}

