private fun getVideoUrlForExercise(exerciseName: String): String {
    val baseUrl = "https://storage.googleapis.com/fitness-videos-glowupp/"
    val normalizedName = exerciseName.trim().replace(Regex("[\\s-]+"), "_").replace(Regex("[^a-zA-Z0-9_]"), "")
    return "${baseUrl}${normalizedName}_Female.mp4"
}

private sealed class WorkoutState {
    object Loading : WorkoutState()
    data class Exercise(val index: Int) : WorkoutState()
    data class Rest(val nextIndex: Int, val restSeconds: Int = 60) : WorkoutState()
    data class Celebration(val results: List<ExerciseResult>, val skipped: List<String>, val isExtra: Boolean) : WorkoutState()
    data class Report(val results: List<ExerciseResult>, val skipped: List<String>) : WorkoutState()
    data class Preview(val warmup: List<ExerciseData>, val main: List<ExerciseData>) : WorkoutState()
    data class Error(val message: String) : WorkoutState()
}

private data class ExerciseResult(
    val name: String,
    val activeMinutes: Double,
    val restMinutes: Double,
    val caloriesKcal: Int,
    val difficultyRating: Int = 1,
    /** Ponovitve opravljene v tej seji — shranjeno za Volume Progression (Faza 12). */
    val reps: Int = 0,
    /** Seti opravljeni v tej seji — shranjeno za Volume Progression (Faza 12). */
    val sets: Int = 0,
    /** Teža v kg (0f = telesna teža) — za prihodnje weight-tracking feature. */
    val weightKg: Float = 0f
)

private data class ExerciseData(
    val name: String,
    val description: String,
    val caloriesPerMinPerKg: Double,
    val difficulty: Int, // Exercise difficulty level (1-10)
    val sets: Int,
    val reps: Int,
    val repsDisplay: String = "12",
    val restSeconds: Int,
    val durationMinutesOverride: Double? = null,
    val durationSecondsOverride: Int? = null,
    val secondsPerRepOverride: Double? = null,
    val videoUrl: String? = null,
    val isWarmup: Boolean = false,
    val executionTips: List<String> = emptyList() // Execution tips to display
)

// Helper: Calculate dynamic rest time based on difficulty & user experience level
// Reference: difficulty=10, experience=10 → 60s
// Less experienced → more rest, easier exercise → less rest
private fun calculateDynamicRestTime(
    baseDifficulty: Int, // 1-10 from exercise
    userExperienceLevel: Int, // Beginner=3, Intermediate=6, Advanced=9
    baseRestSeconds: Int // From JSON (used as fallback reference)
): Int {
    // Base rest scales linearly with difficulty: diff 10 → 60s, diff 5 → 30s, diff 1 → 6s
    val difficultyBase = baseDifficulty * 6.0

    // Experience adjustment: exp 10 → 1.0x (no change), exp 1 → 1.5x (50% more rest)
    // Formula: multiplier = 1.0 + (10 - experience) * 0.055
    val experienceMultiplier = 1.0 + (10 - userExperienceLevel.coerceIn(1, 10)) * 0.055

    val dynamicRest = (difficultyBase * experienceMultiplier).toInt()

    // Cap between 20-120 seconds
    return dynamicRest.coerceIn(20, 120)
}

// Helper: Calculate calories based on ACTUAL time spent on exercise
private fun calculateActualCalories(
    caloriesPerKgPerHour: Double,
    userWeightKg: Double,
    actualMinutes: Double // ACTUAL time user spent on exercise
): Int {
    // Convert per-hour to per-minute
    val caloriesPerKgPerMin = caloriesPerKgPerHour / 60.0
    val totalCalories = caloriesPerKgPerMin * userWeightKg * actualMinutes
    return totalCalories.toInt().coerceAtLeast(1)
}

@Composable
fun WorkoutSessionScreen(
    currentPlan: PlanResult?,
    onBack: () -> Unit,
    onFinished: () -> Unit,
    onXPAdded: () -> Unit = {},
    isExtra: Boolean = false,
    extraFocusAreas: List<String> = emptyList(),   // fokus izbran v GenerateWorkoutScreen
    extraEquipment: Set<String> = emptySet(),       // oprema izbrana v GenerateWorkoutScreen
    onBadgeUnlocked: (Badge) -> Unit = {}
) {
    val context = LocalContext.current
    // Replaced ExerciseCache
    LaunchedEffect(Unit) { withContext(Dispatchers.IO) { AdvancedExerciseRepository.init(context.assets.open("exercises.json").bufferedReader().use { it.readText() }) } }

    val vm: BodyModuleHomeViewModel = viewModel(factory = ViewModelProvider.AndroidViewModelFactory.getInstance(context.applicationContext as Application))
    // ✅ Firestore SSOT: collectiramo state enkrat za celoten composable
    val vmUiState by vm.ui.collectAsState()

    // ── Faza 12: WorkoutSessionViewModel za Firestore Bridge + generiranje ───────
    val workoutVm: WorkoutSessionViewModel = viewModel(
        factory = ViewModelProvider.AndroidViewModelFactory.getInstance(
            context.applicationContext as Application
        )
    )
    val isProgressiveOverload by workoutVm.isProgressiveOverload.collectAsState()

    /** Shranjeni fokus te seje (za CompleteWorkoutSession → workoutDoc.focusAreas). */
    var currentFocusAreas by remember { mutableStateOf(emptySet<String>()) }

    var userWeightKg by remember { mutableStateOf(70.0) }
    val uid = remember { FirestoreHelper.getCurrentUserDocId() }
    LaunchedEffect(Unit) {
        try {
            val weight = withContext(Dispatchers.IO) {
                FirestoreHelper.fetchLatestWeightKg()
            }
            if (weight != null && weight > 0) {
                userWeightKg = weight
            }
        } catch(_: Exception) {}
    }

    var currentSessionExercises by remember { mutableStateOf<List<ExerciseData>>(emptyList()) }
    var state by remember { mutableStateOf<WorkoutState>(WorkoutState.Loading) }

    var showExitDialog by remember { mutableStateOf(false) }

    BackHandler(enabled = state is WorkoutState.Exercise || state is WorkoutState.Rest || state is WorkoutState.Preview) {
        showExitDialog = true
    }

    if (showExitDialog) {
        AlertDialog(
            onDismissRequest = { showExitDialog = false },
            title = { Text("Exit Workout?") },
            text = { Text("Are you sure you want to exit? Your progress will be lost.") },
            confirmButton = {
                TextButton(
                    onClick = {
                        showExitDialog = false
                        onBack()
                    }
                ) {
                    Text("Exit", color = MaterialTheme.colorScheme.error)
                }
            },
            dismissButton = {
                TextButton(
                    onClick = { showExitDialog = false }
                ) {
                    Text("Cancel")
                }
            }
        )
    }

    // Determine user experience level from plan
    val userExperienceLevel = when (currentPlan?.experience) {
        "Beginner" -> 3
        "Intermediate" -> 6
        "Advanced" -> 9
        else -> 5
    }

    fun mapRefinedToExerciseData(refined: RefinedExercise): ExerciseData {
        // Normalize name: replace underscores with spaces and capitalize words
        val normalizedName = refined.name
            .replace("_", " ")
            .split(" ")
            .joinToString(" ") { word ->
                word.lowercase().replaceFirstChar { it.uppercase() }
            }

        val multiplier = AlgorithmPreferences.getExerciseMultiplier(context.getAlgoSettings(), normalizedName)

        val adjustedSets = (refined.parsedSets * multiplier).toInt().coerceAtLeast(1)
        val adjustedReps = if (refined.parsedReps > 0) (refined.parsedReps * multiplier).toInt().coerceAtLeast(1) else 0

        // Calculate dynamic rest time based on difficulty and user level
        val dynamicRestTime = calculateDynamicRestTime(
            baseDifficulty = refined.difficulty,
            userExperienceLevel = userExperienceLevel,
            baseRestSeconds = refined.recommendedRestSeconds
        )

        return ExerciseData(
            name = normalizedName,
            description = refined.description,
            caloriesPerMinPerKg = refined.caloriesPerKgPerHour / 60.0,
            difficulty = refined.difficulty,
            sets = adjustedSets,
            reps = adjustedReps,
            // Ohrani originalni range string (npr "10-12"), ne zamenjuj z int
            repsDisplay = refined.repsDisplay,
            restSeconds = dynamicRestTime,
            durationSecondsOverride = if (refined.parsedReps == 0) ((60 * multiplier).toInt()) else null,
            videoUrl = refined.videoUrl.takeIf { it.isNotEmpty() },
            executionTips = refined.executionTips
        )
    }

    LaunchedEffect(currentPlan, isExtra, extraFocusAreas) {
        state = WorkoutState.Loading
        withContext(Dispatchers.IO) {
            AdvancedExerciseRepository.init(context.assets.open("exercises.json").bufferedReader().use { it.readText() })
        }

        // Check if plan exists - if not, immediately go back
        if (currentPlan == null) {
            onBack() // Navigate back to home screen
            return@LaunchedEffect
        }

        // Determine user experience factor (Beginner=3, Intermediate=6, Advanced=9)
        // Used in calculateDynamicRestTime() via AlgorithmPreferences
        AlgorithmPreferences.initDifficultyForPlan(context.getAlgoSettings(), currentPlan.experience)

        // Določi ciljno težavnost glede na recovery/catchup/normalen način
        val isRecovery = AlgorithmPreferences.isRecoveryMode(context.getAlgoSettings())

        // ✅ SSOT: beri weeklyTarget/weeklyDone/planDay iz BodyModuleHomeViewModel (Firestore), ne bm_prefs
        // ANTI RACE-CONDITION (Faza 31.8): počakamo da LoadMetrics konča preden beremo planDay.
        // vm.ui.value.planDay = 1 (default) če Firestore ni vrnil še odgovora → napačen trening generiran.
        // vm.ui.filter { !it.isLoading }.first() suspenda dokler isLoading → false (Firestore vrne pravo vrednost).
        // Varno: StateFlow.first() ne blokira vedno — vrne takoj ko je isLoading=false.
        val loadedUiState = vm.ui.filter { !it.isLoading }.first()
        val weeklyTarget = loadedUiState.weeklyTarget.takeIf { it > 0 } ?: 3
        val weeklyDone = loadedUiState.weeklyDone

        val targetDifficulty: Float = when {
            isRecovery -> {
                // Recovery: linearna interpolacija od 50% do 100% težavnosti skozi teden
                AlgorithmPreferences.getRecoveryDayDifficulty(context.getAlgoSettings(), weeklyDone, weeklyTarget)
            }
            else -> {
                AlgorithmPreferences.getCurrentDifficulty(context.getAlgoSettings(), currentPlan.experience)
            }
        }

        val goal = when (currentPlan.goal) {
            "Build muscle" -> WorkoutGoal.MUSCLE_GAIN
            "Lose fat" -> WorkoutGoal.WEIGHT_LOSS
            "Recomposition" -> WorkoutGoal.STRENGTH
            "Improve endurance" -> WorkoutGoal.ENDURANCE
            else -> WorkoutGoal.GENERAL_FITNESS
        }

        // ── Focus določitev ──────────────────────────────────────────────────
        val dailyFocus: Set<String>

        if (isExtra) {
            // Extra workout: fokus DIREKTNO iz parametra — kar je uporabnik izbral v GenerateWorkoutScreen
            // Ne beremo iz plana, ne beremo iz Firestorea — SAMO to kar je prišlo kot parameter
            val focus = extraFocusAreas
                .filter { !it.equals("None", ignoreCase = true) }
                .ifEmpty { listOf("Full Body") }
            dailyFocus = focus.toSet()
        } else {
            // Navaden workout: rotacija fokusa po planDay
            val rawFocus = currentPlan.focusAreas.ifEmpty {
                val profile = UserProfileManager.loadProfile(uid ?: "")
                profile.focusAreas.ifEmpty { listOf("Full Body") }
            }
            val allFocus = if (rawFocus.any { it.equals("None", ignoreCase = true) }) {
                listOf("Full Body")
            } else {
                rawFocus
            }
            // ✅ SSOT: beri plan_day iz loadedUiState (že počakanega/naložen Firestore snapshot) namesto bm_prefs
            val planDay = loadedUiState.planDay.coerceAtLeast(1)
            dailyFocus = if (allFocus.any {
                    it.equals("Full Body", ignoreCase = true) ||
                    it.equals("Balance", ignoreCase = true)
                } || allFocus.isEmpty()) {
                setOf("Full Body")
            } else {
                // Štej samo workout dni (ne rest dni) do planDay — beri iz currentPlan.weeks
                val workoutDayIndex: Int = run {
                    val planWeeks = currentPlan.weeks
                    if (planWeeks.isNotEmpty()) {
                        var count = 0
                        for (week in planWeeks) {
                            for (day in week.days) {
                                if (day.dayNumber >= planDay) break
                                if (!day.isRestDay) count++
                            }
                        }
                        count
                    } else {
                        (planDay - 1)
                    }
                }
                val index = workoutDayIndex % allFocus.size
                setOf(allFocus[index])
            }
        }

        // Equipment: za extra workout direktno iz parametra, sicer iz plana
        val equipment: Set<String>
        if (isExtra && extraEquipment.isNotEmpty()) {
            equipment = extraEquipment.map { it.trim().lowercase() }.toSet()
        } else {
            val rawEquipment = currentPlan.equipment.ifEmpty {
                val profile = UserProfileManager.loadProfile(uid ?: "")
                profile.equipment
            }
            equipment = if (rawEquipment.isNotEmpty()) {
                rawEquipment.map { it.trim().lowercase() }.toSet()
            } else if (currentPlan.trainingLocation.equals("Gym", ignoreCase = true)) {
                AdvancedExerciseRepository.getAllEquipment()
            } else {
                setOf("bodyweight")
            }
        }

        Log.d("WorkoutSession", "Focus: $dailyFocus (from plan: ${currentPlan.focusAreas})")
        Log.d("WorkoutSession", "Equipment: $equipment (from plan: ${currentPlan.equipment})")

        // ── Shrani fokus za CompleteWorkoutSession (Faza 12) ────────────────────
        currentFocusAreas = dailyFocus

        // ── Reset + delegiraj generiranje na WorkoutSessionViewModel ────────────
        // ViewModel: 1) fetch Firestore profil (gender) + zadnja seja (Memory Bridge)
        //            2) loadParamsWithOverrides (SSOT)
        //            3) generateWorkout + applyVolumeProgression
        workoutVm.reset()  // Zagotovi Idle → LoadingHistory prehod brez race condition
        workoutVm.prepareWorkout(
            focusAreas         = dailyFocus,
            equipment          = equipment,
            planDay            = vmUiState.planDay.coerceAtLeast(1),
            exerciseCount      = (currentPlan.sessionLength / 4).coerceAtLeast(4).coerceAtMost(15),
            durationMinutes    = currentPlan.sessionLength,
            targetDifficulty   = targetDifficulty,
            goalFromPlan       = goal,
            planExperience     = currentPlan.experience ?: ""
        )

        // ── Počakaj na rezultat (suspending — dokler ni Ready ali Error) ────────
        val genResult = workoutVm.state.first {
            it is WorkoutGenerationState.Ready || it is WorkoutGenerationState.Error
        }

        when (genResult) {
            is WorkoutGenerationState.Ready -> {
                val generatedList = genResult.exercises.map { mapRefinedToExerciseData(it) }
                if (generatedList.isEmpty()) {
                    state = WorkoutState.Error("Could not generate workout. Please check your settings.")
                } else {
                    currentSessionExercises = generatedList.mapIndexed { index, ex ->
                        ex.copy(isWarmup = index < 2)
                    }
                    val warmup = currentSessionExercises.filter { it.isWarmup }
                    val main   = currentSessionExercises.filter { !it.isWarmup }
                    state = WorkoutState.Preview(warmup, main)
                }
            }
            is WorkoutGenerationState.Error -> {
                state = WorkoutState.Error(genResult.message)
            }
            else -> state = WorkoutState.Error("Could not generate workout. Please check your settings.")
        }
    }

    val results = remember { mutableStateListOf<ExerciseResult>() }
    val skippedExercises = remember { mutableStateListOf<String>() }
    var skipCount by remember { mutableIntStateOf(0) }
    val maxSkips = 3

    Box(modifier = Modifier.fillMaxSize().background(MaterialTheme.colorScheme.background), contentAlignment = Alignment.Center) {
        when (val s = state) {
            is WorkoutState.Loading -> {
                CircularProgressIndicator()
            }
            is WorkoutState.Error -> {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    Text(s.message, color = MaterialTheme.colorScheme.error)
                    Button(onClick = onBack) { Text("Back") }
                }
            }
            is WorkoutState.Preview -> {
                //  Faza 12: Progressive Overload badge — "Danes močneje!"
                if (isProgressiveOverload) {
                    Column(modifier = Modifier.fillMaxSize()) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(MaterialTheme.colorScheme.primaryContainer)
                                .padding(vertical = 8.dp, horizontal = 16.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(
                                " Danes močneje! Napredek +5% detektiran",
                                style = MaterialTheme.typography.labelLarge,
                                color = MaterialTheme.colorScheme.onPrimaryContainer,
                                textAlign = TextAlign.Center
                            )
                        }
                        Box(modifier = Modifier.weight(1f)) {
                            PreviewScreen(1, s.warmup, s.main,
                                onStart = { state = WorkoutState.Exercise(0) },
                                onBack = onBack
                            )
                        }
                    }
                } else {
                    PreviewScreen(1, s.warmup, s.main, onStart = { state = WorkoutState.Exercise(0) }, onBack = onBack)
                }
            }
            is WorkoutState.Rest -> {
                RestScreen(s.restSeconds, onSkip = { state = WorkoutState.Exercise(s.nextIndex) }) {
                    state = WorkoutState.Exercise(s.nextIndex)
                }
            }
            is WorkoutState.Exercise -> {
                val ex = currentSessionExercises.getOrNull(s.index)
                if (ex != null) {
                    ExerciseScreen(ex, s.index, currentSessionExercises.size, userWeightKg, skipCount, maxSkips,
                        onPrevious = { if (s.index > 0) state = WorkoutState.Exercise(s.index - 1) },
                        onSkip = {
                            skippedExercises.add(ex.name); skipCount++
                            if (s.index < currentSessionExercises.size - 1) state = WorkoutState.Rest(s.index+1, ex.restSeconds) else state = WorkoutState.Report(results, skippedExercises)
                        },
                        onContinue = { r ->
                            results.add(r)
                            if (s.index < currentSessionExercises.size - 1) state = WorkoutState.Rest(s.index+1, ex.restSeconds) else state = WorkoutState.Celebration(results, skippedExercises, isExtra)
                        },
                        onEndWorkout = { onBack() }
                    )
                }
            }
            is WorkoutState.Celebration -> {
                // ADDED: P1 UX Improvement - Next day preview
                // ✅ SSOT: beri plan_day iz BodyModuleHomeViewModel (Firestore) namesto bm_prefs
                val currentDay = vmUiState.planDay
                val nextDayNumber = currentDay + 1
                val nextDay = currentPlan?.weeks?.flatMap { it.days }?.firstOrNull { it.dayNumber == nextDayNumber }
                val nextDayPreview = when {
                    nextDay == null -> null
                    nextDay.isRestDay -> "Tomorrow: Rest Day "
                    else -> "Tomorrow: ${nextDay.focusLabel} Focus "
                }

                WorkoutCelebrationScreen(
                    isExtra = s.isExtra,
                    nextDayPreview = nextDayPreview,
                    planDay = vmUiState.planDay,  // ✅ Firestore SSOT prek ViewModel
                    streakDays = vmUiState.streakDays, // ✅ Firestore SSOT — ne bm_prefs
                    onContinue = { state = WorkoutState.Report(s.results, s.skipped) }
                )
            }
            is WorkoutState.Report -> {
                WorkoutReportScreen(s.results, s.skipped) {
                    // Uporabi uid iz remember{} (definiran zgoraj) — ne kliči getCurrentUserDocId() znova
                    if (uid != null) {
                       // SAMO AchievementStore skrbi za XP in badge preverjanje
                       // Logic moved to ViewModel to prevent double-counting and ensure transactional safety
                       results.forEach { r ->
                           AlgorithmPreferences.saveExerciseFeedback(context.getAlgoSettings(), r.name, r.difficultyRating)
                       }

                    }
                    vm.handleIntent(
                        BodyHomeIntent.CompleteWorkoutSession(
                        email = FirebaseAuth.getInstance().currentUser?.email ?: "",
                        isExtraWorkout = isExtra,
                        exerciseResults = results.map { r ->
                            mapOf(
                                "name"          to r.name,
                                "activeMinutes" to r.activeMinutes,
                                "restMinutes"   to r.restMinutes,
                                "caloriesKcal"  to r.caloriesKcal,
                                "difficulty"    to r.difficultyRating,
                                // Faza 12: reps/sets za Volume Progression (fetchLastSessionForFocus)
                                "reps"          to r.reps,
                                "sets"          to r.sets,
                                "weightKg"      to r.weightKg
                            )
                        },
                        // Faza 12: shrani fokus v workoutDoc za Memory Bridge iskanje
                        focusAreas = currentFocusAreas.toList(),
                        totalKcal = results.sumOf { it.caloriesKcal },
                        totalTimeMin = results.sumOf { it.activeMinutes + it.restMinutes },
                        onCompletion = { result: WorkoutCompletionResult? ->
                            // Handle badges and navigation only AFTER save is complete
                            if (result != null) {
                                result.unlockedBadges.firstOrNull()?.let { badgeId ->
                                    // Poiščemo Badge objekt iz BadgeDefinitions po ID-ju (unlockedBadges je List<String>)
                                    val badge = BadgeDefinitions.ALL_BADGES
                                        .find { it.id == badgeId }
                                    if (badge != null) onBadgeUnlocked(badge)
                                }
                            }
                            onXPAdded()
                            onFinished()
                        }
                    ))
                }
            }
        }
    }
}

@OptIn(UnstableApi::class)
@Composable
private fun ExerciseScreen(
    exercise: ExerciseData,
    index: Int,
    total: Int,
    userWeightKg: Double,
    skipCount: Int,
    maxSkips: Int,
    onPrevious: () -> Unit,
    onSkip: () -> Unit,
    onContinue: (ExerciseResult) -> Unit,
    onEndWorkout: () -> Unit = {}
) {
    val context = LocalContext.current
    var selectedDifficulty by remember { mutableStateOf(1) }
    var currentSet by remember(exercise.name) { mutableIntStateOf(1) }
    var isVideoPlaying by remember { mutableStateOf(true) }
    var skipCount by remember { mutableStateOf(0) }

    // TRACK ACTUAL TIME SPENT ON EXERCISE
    var actualTimeSeconds by remember(exercise.name) { mutableStateOf(0) }
    var isTimerRunning by remember(exercise.name) { mutableStateOf(true) }

    // Timer that tracks actual time spent on this exercise
    LaunchedEffect(exercise.name, isTimerRunning) {
        while (isTimerRunning) {
            delay(1000) // 1 second
            actualTimeSeconds++
        }
    }

    val isTimed = exercise.reps <= 0 && exercise.durationSecondsOverride != null

    // Calculate ESTIMATED time (for display purposes only — currently not shown in UI)
    val durOverride = exercise.durationSecondsOverride
    @Suppress("UNUSED_VARIABLE")
    val estimatedMinutes = if (isTimed && durOverride != null) {
        (exercise.sets * durOverride) / 60.0
    } else {
        val repSec = exercise.secondsPerRepOverride ?: 3.0
        val reps = if (exercise.reps > 0) exercise.reps else 12
        (exercise.sets * reps * repSec) / 60.0
    }

    var showEndConfirm by remember { mutableStateOf(false) }

    if (showEndConfirm) {
        AlertDialog(
            onDismissRequest = { showEndConfirm = false },
            title = { Text("End workout?") },
            text = { Text("Are you sure you want to end the workout early?") },
            confirmButton = {
                Button(
                    onClick = { showEndConfirm = false; onEndWorkout() },
                    colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.error)
                ) { Text("End", color = MaterialTheme.colorScheme.onError) }
            },
            dismissButton = {
                TextButton(onClick = { showEndConfirm = false }) { Text("Continue") }
            }
        )
    }

    Column(modifier = Modifier.fillMaxSize().padding(16.dp).verticalScroll(rememberScrollState()), horizontalAlignment = Alignment.CenterHorizontally) {
        // Top row: workout badge + End Workout gumb
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                if (exercise.isWarmup) " WARM-UP" else " MAIN WORKOUT",
                style = MaterialTheme.typography.labelLarge,
                color = if (exercise.isWarmup) MaterialTheme.colorScheme.secondary else MaterialTheme.colorScheme.primary,
                fontWeight = FontWeight.Bold
            )
            TextButton(
                onClick = { showEndConfirm = true },
                colors = ButtonDefaults.textButtonColors(contentColor = MaterialTheme.colorScheme.error)
            ) {
                Text("End workout", fontSize = 13.sp, fontWeight = FontWeight.SemiBold)
            }
        }

        Text("Exercise ${index+1}/$total")
        LinearProgressIndicator(progress = { (index+1f)/total }, modifier = Modifier.fillMaxWidth())

        Spacer(Modifier.height(8.dp))

        // Video player - auto plays by default, no toggle button
        val vidUrl = exercise.videoUrl ?: getVideoUrlForExercise(exercise.name)

        // Expanded video player
        Box(modifier = Modifier.fillMaxWidth().height(250.dp)) {
            var isBuffering by remember(vidUrl) { mutableStateOf(true) }
            var isVideoReady by remember(vidUrl) { mutableStateOf(false) }
            val player = remember(vidUrl) {
                ExoPlayer.Builder(context).build().apply {
                    setMediaItem(MediaItem.fromUri(vidUrl))
                    repeatMode = Player.REPEAT_MODE_ALL
                    addListener(object : Player.Listener {
                        override fun onPlaybackStateChanged(playbackState: Int) {
                            isBuffering = playbackState == Player.STATE_BUFFERING
                            if (playbackState == Player.STATE_READY) {
                                isVideoReady = true
                            }
                        }
                    })
                    prepare()
                    playWhenReady = true
                }
            }

            LaunchedEffect(isVideoPlaying) {
                player.playWhenReady = isVideoPlaying
            }

            DisposableEffect(player) { onDispose { player.release() } }

            AndroidView(
                factory = { ctx -> PlayerView(ctx).apply {
                    this.player = player
                    useController = true
                    setShutterBackgroundColor(android.graphics.Color.TRANSPARENT)
                    setBackgroundColor(android.graphics.Color.TRANSPARENT)
                } },
                modifier = Modifier
                    .fillMaxSize()
                    .clip(RoundedCornerShape(12.dp))
                    .graphicsLayer(alpha = if (isVideoReady) 1f else 0f)
            )

            if (isBuffering || !isVideoReady) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(Color.Transparent),
                    contentAlignment = Alignment.Center
                ) {
                    androidx.compose.material3.CircularProgressIndicator(
                        color = MaterialTheme.colorScheme.primary
                    )
                }
            }
        }

        Spacer(Modifier.height(8.dp))

        Text(exercise.name, style = MaterialTheme.typography.headlineLarge, textAlign = TextAlign.Center)

        // Show current set progress
        Text(
            "Set $currentSet / ${exercise.sets}",
            style = MaterialTheme.typography.titleMedium,
            fontWeight = FontWeight.Bold,
            color = MaterialTheme.colorScheme.primary
        )

        // Show actual time spent on exercise
        Text(
            "Time: ${actualTimeSeconds / 60}:${(actualTimeSeconds % 60).toString().padStart(2, '0')}",
            style = MaterialTheme.typography.bodyLarge,
            color = MaterialTheme.colorScheme.secondary,
            fontWeight = FontWeight.SemiBold
        )

        if (isTimed) {
             Text("Duration: ${exercise.durationSecondsOverride}s per set")
        } else {
             Text("${exercise.repsDisplay} reps per set")
        }

        Spacer(Modifier.height(8.dp))
        Text(exercise.description, style = MaterialTheme.typography.bodyMedium, textAlign = TextAlign.Center)

        // Display execution tips if available
        if (exercise.executionTips.isNotEmpty()) {
            var showTips by remember { mutableStateOf(false) }
            Spacer(Modifier.height(8.dp))
            TextButton(onClick = { showTips = !showTips }) {
                Text(if (showTips) "Hide Execution Tips ↑" else "Show Execution Tips ↓", color = MaterialTheme.colorScheme.primary)
            }
            if (showTips) {
                Spacer(Modifier.height(4.dp))
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.tertiaryContainer,
                        contentColor = MaterialTheme.colorScheme.onTertiaryContainer
                    )
                ) {
                    Column(modifier = Modifier.padding(12.dp)) {
                        Text(
                            " Execution Tips:",
                            fontWeight = FontWeight.Bold,
                            fontSize = 14.sp
                        )
                        Spacer(Modifier.height(4.dp))
                        exercise.executionTips.forEach { tip ->
                            Text(
                                "• $tip",
                                fontSize = 12.sp,
                                modifier = Modifier.padding(start = 8.dp, top = 2.dp)
                            )
                        }
                    }
                }
            }
        }

        Spacer(Modifier.weight(1f))

        // Action buttons: Prev / Set Done / Skip
        Row(Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
            Button(onClick = {
                HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.CLICK)
                onPrevious()
            }) { Text("Prev") }
            Button(onClick = {
                if (currentSet < exercise.sets) {
                    HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.SUCCESS)
                    currentSet++
                } else {
                    HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.HEAVY_CLICK)
                    // Stop timer
                    isTimerRunning = false

                    // Calculate ACTUAL time spent
                    val actualMinutes = actualTimeSeconds / 60.0

                    // Assume 80% was active time, 20% was rest (rough estimate)
                    val actualActiveMin = actualMinutes * 0.8
                    val actualRestMin = actualMinutes * 0.2

                    // Calculate calories based on ACTUAL time spent
                    val actualKcal = calculateActualCalories(
                        caloriesPerKgPerHour = exercise.caloriesPerMinPerKg * 60.0,
                        userWeightKg = userWeightKg,
                        actualMinutes = actualActiveMin
                    ) + (actualRestMin * 1.0 * userWeightKg).toInt()

                    // Apply weight/difficulty adjustment based on feedback
                    // 0=Too Easy → increase multiplier, 1=OK → keep, 2=Too Hard → decrease
                    val adjustmentFactor = when (selectedDifficulty) {
                        0 -> 1.05f  // Too Easy: increase by 5%
                        2 -> 0.95f  // Too Hard: decrease by 5%
                        else -> 1.0f // OK: no change
                    }
                    if (adjustmentFactor != 1.0f) {
                        val currentMultiplier = AlgorithmPreferences.getExerciseMultiplier(context.getAlgoSettings(), exercise.name)
                        val newMultiplier = (currentMultiplier * adjustmentFactor).coerceIn(0.5f, 2.0f)
                        AlgorithmPreferences.saveExerciseMultiplier(context.getAlgoSettings(), exercise.name, newMultiplier)
                    }

                    // Finish exercise with ACTUAL data
                    onContinue(ExerciseResult(
                        name = exercise.name,
                        activeMinutes = actualActiveMin,
                        restMinutes = actualRestMin,
                        caloriesKcal = actualKcal,
                        difficultyRating = selectedDifficulty,
                        // Faza 12: shrani reps/sets za Volume Progression
                        reps = exercise.reps.coerceAtLeast(0),
                        sets = exercise.sets.coerceAtLeast(1)
                    ))
                }
            }) {
                Text(if (currentSet < exercise.sets) "Set Done" else "Finish")
            }
            Button(onClick = {
                HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.CLICK)
                onSkip()
            }, enabled = skipCount < maxSkips) { Text("Skip") }
        }

        Spacer(Modifier.height(12.dp))

        // Feedback section - BELOW action buttons, with text labels
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 4.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.Center
        ) {
            Text(
                "How was it?",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                modifier = Modifier.padding(end = 8.dp)
            )
            listOf("Too Easy", "OK", "Too Hard").forEachIndexed { i, label ->
                FilterChip(
                    selected = selectedDifficulty == i,
                    onClick = { selectedDifficulty = i },
                    label = { Text(label, fontSize = 12.sp) },
                    modifier = Modifier.padding(horizontal = 2.dp)
                )
            }
        }

        Spacer(Modifier.height(8.dp))
    }
}

@Composable
private fun RestScreen(restSeconds: Int, onSkip: () -> Unit, onComplete: () -> Unit) {
    val context = LocalContext.current
    var time by remember { mutableIntStateOf(restSeconds) }
    LaunchedEffect(time) {
        if (time > 0) { delay(1000); time-- } else onComplete()
    }
    Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
        Column(horizontalAlignment = Alignment.CenterHorizontally) {
            Text("REST", style = MaterialTheme.typography.displayLarge)
            Text("$time s", style = MaterialTheme.typography.displayMedium)
            Spacer(Modifier.height(8.dp))
            Text("${restSeconds}s based on exercise difficulty", style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
            Spacer(Modifier.height(16.dp))
            Button(onClick = {
                HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.CLICK)
                onSkip()
            }) { Text("Skip") }
            Button(onClick = {
                HapticFeedback.performHapticFeedback(context, HapticFeedback.FeedbackType.LIGHT_CLICK)
                time += 10
            }) { Text("+10s") }
        }
    }
}

@Composable
private fun PreviewScreen(day: Int, warmup: List<ExerciseData>, main: List<ExerciseData>, onStart: () -> Unit, onBack: () -> Unit) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
            .verticalScroll(rememberScrollState()),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Row(verticalAlignment = Alignment.CenterVertically) {
            IconButton(onClick = onBack) {
                Icon(
                    Icons.AutoMirrored.Filled.ArrowBack,
                    contentDescription = "Back"
                )
            }
            Spacer(Modifier.width(8.dp))
            Text("Workout Preview", style = MaterialTheme.typography.headlineMedium)
        }

        if (warmup.isNotEmpty()) {
            Text("Warm-up", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.primary)
            warmup.forEach { ex -> PreviewExerciseCard(ex) }
        }

        if (main.isNotEmpty()) {
            Text("Main Workout", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.primary)
            main.forEachIndexed { i, ex -> PreviewExerciseCard(ex, number = i + 1) }
        }

        Spacer(Modifier.height(16.dp))
        Button(
            onClick = onStart,
            modifier = Modifier.fillMaxWidth().height(56.dp),
            colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.primary)
        ) {
            Text("Start Workout", fontSize = 18.sp, fontWeight = FontWeight.Bold)
        }
    }
}

@Composable
private fun PreviewExerciseCard(ex: ExerciseData, number: Int? = null) {
    Card(
            modifier = Modifier.fillMaxWidth(),
            colors = CardDefaults.cardColors(
                containerColor = MaterialTheme.colorScheme.surfaceVariant
            )
        ) {
            Row(
                modifier = Modifier.padding(16.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Optional number
                if (number != null) {
                    Text(
                        text = "$number.",
                        style = MaterialTheme.typography.titleLarge,
                        fontWeight = FontWeight.Bold,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                        modifier = Modifier.padding(end = 16.dp)
                    )
                }

                Column(modifier = Modifier.weight(1f)) {
                    Text(ex.name, style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.SemiBold)
                    Spacer(Modifier.height(4.dp))
                    val details = if (ex.durationSecondsOverride != null && ex.reps == 0) {
                         if (ex.durationSecondsOverride > 0) "${ex.sets} sets × ${ex.durationSecondsOverride}s" else "${ex.sets} sets"
                    } else {
                        "${ex.sets} sets × ${ex.repsDisplay}"
                    }
                    Text(details, style = MaterialTheme.typography.bodyMedium, color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            }
        }
}

@Composable
private fun WorkoutReportScreen(results: List<ExerciseResult>, skipped: List<String>, onDone: () -> Unit) {
    var selectedFeedback by remember { mutableStateOf<String?>(null) }
    var isSubmitting by remember { mutableStateOf(false) }
    val context = LocalContext.current

    Column(Modifier.fillMaxSize().padding(16.dp).verticalScroll(rememberScrollState())) {
        Text("Done! ", style = MaterialTheme.typography.headlineLarge, fontWeight = FontWeight.Bold)
        Spacer(Modifier.height(8.dp))

        // ADDED: Confirmation banner (P0 UX Improvement)
        Card(
            modifier = Modifier.fillMaxWidth().padding(bottom = 16.dp),
            colors = CardDefaults.cardColors(
                containerColor = UppColors.Success.copy(alpha = 0.15f)
            )
        ) {
            Row(
                modifier = Modifier.padding(16.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text("✅", fontSize = 24.sp)
                Spacer(Modifier.width(12.dp))
                Column {
                    Text("Workout Saved", fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onSurface)
                    Text("Saved to history • +XP • Streak updated", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            }
        }

        val totalKcal = results.sumOf { it.caloriesKcal }
        Text("Total: $totalKcal kcal burned", style = MaterialTheme.typography.titleMedium, color = MaterialTheme.colorScheme.primary)
        Spacer(Modifier.height(12.dp))
        results.forEach { Text("• ${it.name}: ${it.caloriesKcal} kcal") }

        Spacer(Modifier.height(24.dp))
        Text("How was the workout?", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.SemiBold)
        Spacer(Modifier.height(8.dp))
        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            listOf("Too Short", "Just Right", "Too Long").forEach { feedback ->
                val isSelected = selectedFeedback == feedback
                Button(
                    onClick = {
                        selectedFeedback = feedback
                        val adjustment = when (feedback) {
                            "Too Short" -> 1
                            "Too Long" -> -1
                            else -> 0
                        }
                        AlgorithmPreferences.saveGlobalFeedback(context.getAlgoSettings(), adjustment)
                        AppToast.showSuccess(context, "Thanks! Adjusting next workout...")
                    },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.surfaceVariant,
                        contentColor = if (isSelected) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurfaceVariant
                    )
                ) {
                    Text(feedback)
                }
            }
        }

        Spacer(Modifier.weight(1f))
        Button(
            onClick = {
                if (!isSubmitting) {
                    isSubmitting = true
                    onDone()
                }
            },
            modifier = Modifier.fillMaxWidth().height(56.dp),
            enabled = !isSubmitting
        ) {
            if (isSubmitting) {
                CircularProgressIndicator(modifier = Modifier.size(24.dp), color = MaterialTheme.colorScheme.onPrimary)
            } else {
                Text("Finish")
            }
        }
    }
}

@Composable
private fun WorkoutCelebrationScreen(
    isExtra: Boolean,
    nextDayPreview: String? = null,
    planDay: Int = 0,         // ✅ Prejeto iz BodyModuleHomeViewModel (Firestore SSOT, ne bm_prefs)
    streakDays: Int = 0,      // ✅ Firestore SSOT prek BodyModuleHomeViewModel.ui.streakDays
    onContinue: () -> Unit
) {
    val scale = remember { Animatable(0f) }
    val streakScale = remember { Animatable(0f) }
    val confettiAlpha = remember { Animatable(0f) }

    LaunchedEffect(Unit) {
        scale.animateTo(1.2f, tween(400, easing = FastOutSlowInEasing))
        scale.animateTo(0.9f, tween(150))
        scale.animateTo(1.0f, tween(150))
        delay(300)
        confettiAlpha.animateTo(1f, tween(500))
        streakScale.animateTo(1.3f, tween(400, easing = FastOutSlowInEasing))
        streakScale.animateTo(1.0f, tween(200))
    }

    val context = LocalContext.current  // ← potrebno za HapticFeedback
    // ✅ streakDays prejmemo kot parameter iz BodyModuleHomeViewModel (Firestore SSOT)
    val currentStreak = streakDays
    // planDay prejmemo kot parameter iz BodyModuleHomeViewModel (Firestore SSOT)

    // Animate from (current - 1) to (current)
    val startStreak = (currentStreak - 1).coerceAtLeast(0)
    val targetStreak = currentStreak
    val streakAnim = remember { Animatable(startStreak.toFloat()) }

    // Firework animation state for the moment streak changes
    val streakBump = remember { Animatable(1f) }

    LaunchedEffect(Unit) {
        delay(1000) // Wait for initial popup to settle
        streakAnim.animateTo(
            targetValue = targetStreak.toFloat(),
            animationSpec = tween(durationMillis = 1000, easing = FastOutSlowInEasing)
        )
    }

    // Haptics & Bump logic
    LaunchedEffect(streakAnim) {
        var lastVal = startStreak
        snapshotFlow { streakAnim.value.toInt() }
            .collectLatest { current ->
                if (current != lastVal) {
                    lastVal = current
                    // Haptic feedback
                    HapticFeedback.performHapticFeedback(
                        context,
                        HapticFeedback.FeedbackType.HEAVY_CLICK
                    )
                    // Visual bump
                    streakBump.snapTo(1.5f)
                    streakBump.animateTo(1f, tween(300, easing = FastOutSlowInEasing))
                }
            }
    }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(MaterialTheme.colorScheme.background)
            .windowInsetsPadding(WindowInsets.systemBars),
        contentAlignment = Alignment.Center
    ) {
        // Confetti for regular workout
        if (!isExtra) {
            val infiniteTransition = rememberInfiniteTransition(label = "confetti")
            val confettiOffset by infiniteTransition.animateFloat(
                initialValue = 0f, targetValue = 1f,
                animationSpec = infiniteRepeatable(
                    animation = tween(2000),
                    repeatMode = RepeatMode.Restart
                ), label = "confettiOff"
            )
            val confettiColors = listOf(MaterialTheme.colorScheme.secondary, MaterialTheme.colorScheme.primary, UppColors.Success, MaterialTheme.colorScheme.tertiary, UppColors.Blue)
            repeat(30) { i -> // Increased confetti count
                val xPos = (i * 83 % 100) / 100f
                val startY = ((i * 47 + confettiOffset * 100) % 110) / 100f
                Box(modifier = Modifier.fillMaxSize().graphicsLayer(alpha = confettiAlpha.value)) {
                    Box(
                        modifier = Modifier
                            .absoluteOffset(x = (xPos * 400 - 20).dp, y = (startY * 900 - 50).dp)
                            .size(if(i % 3 == 0) 10.dp else 6.dp)
                            .background(confettiColors[i % confettiColors.size], CircleShape)
                    )
                }
            }
        }

        Column(
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center,
            modifier = Modifier.padding(32.dp)
        ) {
            Text(
                text = if (isExtra) "" else "",
                fontSize = 80.sp,
                modifier = Modifier.graphicsLayer(scaleX = scale.value, scaleY = scale.value)
            )
            Spacer(Modifier.height(24.dp))

            if (isExtra) {
                Text(
                    "Extra Workout Done!",
                    fontSize = 28.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onBackground,
                    textAlign = TextAlign.Center,
                    modifier = Modifier.graphicsLayer(scaleX = streakScale.value, scaleY = streakScale.value)
                )
                Spacer(Modifier.height(8.dp))
                Text("You went beyond today's plan! ", fontSize = 16.sp, color = MaterialTheme.colorScheme.onSurfaceVariant, textAlign = TextAlign.Center)
                Spacer(Modifier.height(24.dp))
                val armScale = remember { Animatable(0.8f) }
                LaunchedEffect(Unit) {
                    delay(600)
                    while (true) {
                        armScale.animateTo(1.15f, tween(700))
                        armScale.animateTo(0.95f, tween(500))
                    }
                }
                Text("→", fontSize = 48.sp, modifier = Modifier.graphicsLayer(scaleX = armScale.value, scaleY = armScale.value))
            } else {
                Text("Workout Complete!", fontSize = 28.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onBackground, textAlign = TextAlign.Center)
                Spacer(Modifier.height(20.dp))
                Card(
                    shape = androidx.compose.foundation.shape.RoundedCornerShape(20.dp),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant),
                    modifier = Modifier.fillMaxWidth().graphicsLayer(scaleX = streakScale.value, scaleY = streakScale.value)
                ) {
                    Row(
                        modifier = Modifier.padding(20.dp).fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceEvenly,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            Text("", fontSize = 36.sp)

                            // Animated streak number
                            Text(
                                text = "${streakAnim.value.toInt()}",
                                fontSize = 32.sp,
                                fontWeight = FontWeight.Bold,
                                color = MaterialTheme.colorScheme.secondary,
                                modifier = Modifier.graphicsLayer {
                                    scaleX = streakBump.value
                                    scaleY = streakBump.value
                                }
                            )
                            Text("Day streak", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        }
                        Box(modifier = Modifier.height(60.dp).width(1.dp).background(MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha=0.3f)))
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            // NO CALENDAR ICON - Just text
                            Spacer(Modifier.height(4.dp))
                            Text("Day $planDay", fontSize = 24.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.primary)
                            Text("of your plan", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        }
                    }
                }
                Spacer(Modifier.height(12.dp))
                val motivations = listOf("Keep it up! ", "You're unstoppable! ⚡", "One day at a time! ", "Consistency is key! ", "You're crushing it! ")
                Text(motivations[targetStreak % motivations.size], fontSize = 16.sp, color = MaterialTheme.colorScheme.primary, textAlign = TextAlign.Center, fontWeight = FontWeight.Medium)

                // ADDED: P1 Next Day Preview
                if (!isExtra && nextDayPreview != null) {
                    Spacer(Modifier.height(24.dp))
                    Surface(
                        color = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f),
                        shape = androidx.compose.foundation.shape.RoundedCornerShape(12.dp)
                    ) {
                        Text(
                            text = nextDayPreview,
                            fontSize = 14.sp,
                            fontWeight = FontWeight.SemiBold,
                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                            modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp)
                        )
                    }
                }
            }

            Spacer(Modifier.height(40.dp))
            Button(
                onClick = onContinue,
                modifier = Modifier.fillMaxWidth().height(56.dp),
                colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.primary),
                shape = androidx.compose.foundation.shape.RoundedCornerShape(28.dp)
            ) {
                Text("Continue", fontSize = 18.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onPrimary)
            }
        }
    }
}

private fun Context.getAlgoSettings() =
    SharedPreferencesSettings(this.getSharedPreferences("algorithm_prefs", Context.MODE_PRIVATE))

package com.example.myapplication.viewmodels
import androidx.lifecycle.ViewModel import androidx.lifecycle.viewModelScope import com.example.myapplication.R import com.example.myapplication.data.UserProfile import com.example.myapplication.domain.model.BodyField import com.example.myapplication.domain.model.BodyGoldenRatioResult import com.example.myapplication.domain.model.PlanResult import com.example.myapplication.domain.model.UserDayStatus import com.example.myapplication.domain.gamification.ManageGamificationUseCase import com.example.myapplication.domain.gamification.WorkoutCompletionResult import com.example.myapplication.domain.auth.AuthStateRepository import com.example.myapplication.domain.profile.UserProfileRepository import com.example.myapplication.domain.model.BodyMeasurementEntry import com.example.myapplication.domain.repository.BodyMeasurementsRepository import com.example.myapplication.domain.usecase.CalculateBodyGoldenRatioUseCase import com.example.myapplication.domain.usecase.GetBodyMetricsUseCase import com.example.myapplication.domain.usecase.SaveBodyMeasurementsUseCase import com.example.myapplication.domain.usecase.SwapPlanDaysUseCase import com.example.myapplication.domain.usecase.UpdateBodyMetricsUseCase import com.example.myapplication.domain.usecase.ValidationResult import kotlinx.coroutines.Job import kotlinx.coroutines.channels.Channel import kotlinx.coroutines.flow.MutableSharedFlow import kotlinx.coroutines.flow.MutableStateFlow import kotlinx.coroutines.flow.SharedFlow import kotlinx.coroutines.flow.SharingStarted import kotlinx.coroutines.flow.StateFlow import kotlinx.coroutines.flow.asSharedFlow import kotlinx.coroutines.flow.asStateFlow import kotlinx.coroutines.flow.combine import kotlinx.coroutines.flow.flatMapLatest import kotlinx.coroutines.flow.flowOf import kotlinx.coroutines.flow.receiveAsFlow import kotlinx.coroutines.flow.stateIn import kotlinx.coroutines.launch
/** * Faza 30.9 — Enkratni UI dogodki za BodyModul. * * Razlika od StateFlow: * StateFlow = trajno stanje (kateri zaslon je odprt, ali nalagamo…) * Channel = enkratni dogodek (prikaži Snackbar, navigiraj, zapri dialog) * * Ne smeš shranjevati teh vrednosti v StateFlow — Snackbar bi se ob rotaciji zaslona * prikazal znova. Channel zagotavlja natanko en sprejem. */ sealed interface BodyUiEvent { /** Meritve so bile uspešno shranjene v Firestore. */ data object SaveSuccess : BodyUiEvent /** Napaka med shranjevanjem — prikaži Snackbar z [message]. */ data class Error(val message: String) : BodyUiEvent }
/** * Faza 31.1 — Enoten UI state za Golden Ratio sekcijo. * Faza 31.3 — inputErrorRes: Int? → invalidFields: Set<BodyField> za per-field natančnost. * * Faza 31.6 — Dead code odstranjen: bodyProfile je zdaj private, measurementsHistory izbrisan. * * Nadomešča tri razpršene StateFlow-e (zdaj odstranjene/private): * bodyProfile (private) → pokrit z Loading/Success * goldenRatioResults: StateFlow<Result?> → Success.data * isSaving: StateFlow<Boolean> → Success.isSaving * * Prednosti: * • Atomarni prehodi — UI nikoli ne vidi nedosledne kombinacije vrednosti * • Loading stanje preprečuje vizualno utripanje ("flash of empty content") * • invalidFields: UI obarva SAMO polja, ki so dejansko zunaj meja */ sealed interface GoldenRatioUiState { /** Profil se nalaga iz Firestore — pokaži CircularProgressIndicator. */ data object Loading : GoldenRatioUiState
/** * Profil naložen — pokaži celotni vmesnik z vnosi. * @param profileHeight Višina iz profila (za prikaz in izračun pas/višina razmerja) * @param shoulderInput Faza 31.4 — surovi vnos za ramena (String, ne Double) * @param waistInput Faza 31.4 — surovi vnos za pas * @param hipInput Faza 31.4 — surovi vnos za boke (prazno = ni vnosu) * @param data Rezultat izračuna; null dokler vnos ni veljaven/popoln * @param isSaving true med Firestore batch write — gumb onemogočen * @param invalidFields Set polj, ki so zunaj bioloških meja (30–250 cm). * @param isInputComplete Faza 31.5 — true ko so vsa 4 polja (ramena, pas, boki, višina) * uspešno parsana v vrednosti > 0.0. Ko false + data==null + ni napak, * UI prikaže nevtralen napotek za vnos. */ data class Success( val profileHeight: Double?, val shoulderInput: String = "", val waistInput: String = "", val hipInput: String = "", val data: BodyGoldenRatioResult?, val isSaving: Boolean = false, val invalidFields: Set<BodyField> = emptySet(), val isInputComplete: Boolean = false ) : GoldenRatioUiState
/** * Napaka pri inicializaciji zaslona (npr. izpad Firestore med nalaganjem profila). * NI namenjen validacijskim napakam vnosa — za to se uporablja [Success.invalidFields]. * @param messageRes ID string resursa (R.string.*) — lokalizabilen, brez Context v VM */ data class Error(val messageRes: Int) : GoldenRatioUiState }
/** * Faza 30.1 — Vhodni podatki za telesni Zlati Rez. * shoulderCm/waistCm = 0.0 pomeni: ni vnosa → goldenRatioResults = null. */ data class BodyMeasurementsInput( val shoulderCm: Double = 0.0, val waistCm: Double = 0.0, val hipCm: Double = 0.0, val heightCm: Double = 0.0 // fallback, če profil nima višine )
/** * Faza 31.4 — Surovi tekstovni vnosi za telesne mere. * Nahajajo se v ViewModel StateFlow (ne v lokalni Compose state!) → * preživijo UI state tranzicije (Loading → Success itd.) brez izgube. */ data class BodyMeasurementsInputText( val shoulder: String = "", val waist: String = "", val hip: String = "" )
data class Challenge( val id: String, val title: String, val description: String, val xpReward: Int = 100, val accepted: Boolean = false, val completed: Boolean = false, val iconRes: Int? = null )
/** * UI stanje za Body Home zaslon. * * Faza 21: todayStatus je zdaj tipsko-varni [UserDayStatus] namesto String. */ data class BodyHomeUiState( val streakDays: Int = 0, val streakFreezes: Int = 0, val weeklyDone: Int = 0, val weeklyTarget: Int = 3, val planDay: Int = 1, val totalWorkoutsCompleted: Int = 0, val workoutsToday: Int = 0, val isWorkoutDoneToday: Boolean = false, val dailyKcal: Int = 0, val showCompletionAnimation: Boolean = false, val todayIsRest: Boolean = false, val outdoorSuggestion: String? = null, val errorMessage: String? = null, val isLoading: Boolean = false, /** Tipsko-varni status današnjega dne — nadomešča String "WORKOUT_DONE" itd. */ val todayStatus: UserDayStatus = UserDayStatus.WORKOUT_PENDING, val challenges: List<Challenge> = listOf( Challenge("c1", "30 days sixpack", "Get a sixpack in 30 days. Perform core exercises daily.", 500), Challenge("c2", "30 days pushups", "Improve your pushups in 30 days. Do 50 pushups/day.", 300), Challenge("c3", "Mobility week", "Increase your ROM in 7 days. Stretch every morning.", 150) ) )
sealed class BodyHomeIntent { data class LoadMetrics(val email: String, val plan: PlanResult? = null) : BodyHomeIntent() object CompleteRestDay : BodyHomeIntent() object HideCompletionAnimation : BodyHomeIntent() data class AcceptChallenge(val id: String) : BodyHomeIntent() data class CompleteChallenge(val id: String) : BodyHomeIntent() data class SwapDays(val currentPlan: PlanResult, val dayA: Int, val dayB: Int, val onResult: (PlanResult) -> Unit) : BodyHomeIntent() data class CompleteWorkoutSession( val email: String, val isExtraWorkout: Boolean = false, val totalKcal: Int = 0, val totalTimeMin: Double = 0.0, val exerciseResults: List<Map<String, Any>> = emptyList(), val focusAreas: List<String> = emptyList(), val onCompletion: (WorkoutCompletionResult?) -> Unit = {} ) : BodyHomeIntent() }
data class StreakUpdateEvent(val newStreak: Int, val isRestDay: Boolean = false)
/** * Faza 30.2 — BodyModuleHomeViewModel brez kakršnih koli Firebase SDK klicev. * Faza 30.6 — Dodan BodyMeasurementsRepository za zgodovino meritev. * * Auth stanje pride reaktivno prek [AuthStateRepository] vmesnika. * Profil se avtomatično osvežuje ob spremembi prijave (flatMapLatest). */ class BodyModuleHomeViewModel( private val getBodyMetrics: GetBodyMetricsUseCase, private val updateBodyMetrics: UpdateBodyMetricsUseCase, private val swapPlanDays: SwapPlanDaysUseCase, private val gamificationUseCase: ManageGamificationUseCase? = null, private val userProfileRepository: UserProfileRepository, private val authStateRepository: AuthStateRepository, // Faza 30.6: Repozitorij za shranjevanje in opazovanje zgodovine meritev private val bodyMeasurementsRepository: BodyMeasurementsRepository ) : ViewModel() {
// ── Faza 30.1 — Domain Use Case za telesni Zlati Rez ────────────────────── private val calculateBodyGoldenRatio = CalculateBodyGoldenRatioUseCase()
// ── Faza 30.6 — Use Case za shranjevanje meritev (DI prek konstruktorja) ── private val saveMeasurementsUseCase = SaveBodyMeasurementsUseCase(bodyMeasurementsRepository)
// ── Faza 30.2 — Reaktivni profil brez Firebase v VM ────────────────────── /** * flatMapLatest: ob vsaki spremembi stanja prijave (login/logout) se * avtomatično zamenja na pravi profil ali flowOf(null). * Preživi rotacijo zaslona — ViewModel ostane živ med config change. * * Faza 31.6 — private: profil se ne izpostavlja UI neposredno. * Javni dostop poteka izključno prek goldenRatioUiState. */ private val bodyProfile: StateFlow<UserProfile?> = authStateRepository.observeCurrentUserEmail() .flatMapLatest { email -> if (email != null) userProfileRepository.observeUserProfile(email) else flowOf(null) } .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), null)
// ── Faza 30.1 → Faza 31.4 — Vhodni teksti (String, ne Double) v ViewModel ─ /** * Faza 31.4 — Surovi vnosi so StateFlow v ViewModel (ne lokalni rememberSaveable). * Preživijo vsak UI state transition (Loading ↔ Success) brez izgube vrednosti. */ private val _inputText = MutableStateFlow(BodyMeasurementsInputText())
// ── Faza 30.8 — Stanje shranjevanja (interno — javno prek goldenRatioUiState) ─ private val _isSaving = MutableStateFlow(false)
/** * Faza 31.1 — ENOTEN UI STATE za Golden Ratio sekcijo. * Faza 31.4 — Input strings so del Success stanja → UI vidi točno kar je vtipkal. * * Kombinira 3 vire (bodyProfile + _inputText + _isSaving) v en atomaren tok. * Parsing string→Double se dogaja TUKAJ — UI ostane čist (ne operira s float-i). */ val goldenRatioUiState: StateFlow<GoldenRatioUiState> = combine( bodyProfile, _inputText, _isSaving ) { profile, texts, saving -> // Faza 31.5 — Locale-safe parsing: zamenjaj vejico s piko (slovenska tipkovnica) // "75,5" → "75.5" → 75.5 | "" → 0.0 | "abc" → 0.0 val shoulderCm = texts.shoulder.replace(',', '.').toDoubleOrNull() ?: 0.0 val waistCm = texts.waist.replace(',', '.').toDoubleOrNull() ?: 0.0 val hipCm = texts.hip.replace(',', '.').toDoubleOrNull() ?: 0.0 val heightCm = profile?.height ?: 0.0
// Faza 31.5 — Zastavica za POPOLN vnos: vsa 4 polja > 0 // false → UI prikaže nevtralen napotek; true + data!=null → prikaži rezultat val isInputComplete = shoulderCm > 0.0 && waistCm > 0.0 && hipCm > 0.0 && heightCm > 0.0
when { profile == null -> GoldenRatioUiState.Loading else -> { // Kliči UseCase samo ko sta obe obvezni vrednosti vneseni if (shoulderCm > 0.0 && waistCm > 0.0) { when (val validation = calculateBodyGoldenRatio( shoulderCm = shoulderCm, waistCm = waistCm, hipCm = hipCm, heightCm = heightCm, isMale = profile.gender?.equals("Male", ignoreCase = true) ?: true )) { is ValidationResult.Success -> GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = validation.data, isSaving = saving, invalidFields = emptySet(), isInputComplete = isInputComplete ) is ValidationResult.Invalid -> { android.util.Log.d( "BodyModuleHomeVM", "Per-field napaka: ${validation.invalidFields}" ) GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = null, isSaving = saving, invalidFields = validation.invalidFields, isInputComplete = isInputComplete ) } } } else { // Polja prazna ali nepopolna — čisto stanje GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = null, isSaving = saving, invalidFields = emptySet(), isInputComplete = isInputComplete ) } } } }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), GoldenRatioUiState.Loading)
/** * Faza 31.4 — Posodobi surove vnosne tekste (iz UI TextField). * Parsing string→Double se izvaja v combine, ne tukaj. */ fun updateInputText(shoulder: String, waist: String, hip: String) { _inputText.value = BodyMeasurementsInputText(shoulder, waist, hip) }
/** Faza 30.1 kliče UI ko vnese meritve — obdržano za morebitne klice od drugod. */ fun updateBodyMeasurements( shoulderCm: Double, waistCm: Double, hipCm: Double = 0.0, heightCm: Double = 0.0 ) { // Delegiraj na updateInputText — pretvori nazaj v string za konsistentnost _inputText.value = BodyMeasurementsInputText( shoulder = if (shoulderCm > 0) shoulderCm.toString() else "", waist = if (waistCm > 0) waistCm.toString() else "", hip = if (hipCm > 0) hipCm.toString() else "" ) }
// ── Faza 30.9 — Enkratni UI dogodki (Channel = natanko en sprejem) ──────── /** * Channel<BodyUiEvent>: pošiljamo enkratne dogodke (Snackbar, navigacija…). * receiveAsFlow() v UI posluša z LaunchedEffect. * * Zakaj Channel in ne SharedFlow: * SharedFlow (replay=0) bi izgubil dogodek, če UI ni še naročen. * Channel.BUFFERED ohrani sporočilo dokler ga UI ne prebere. */ private val _uiEvent = Channel<BodyUiEvent>(Channel.BUFFERED) val uiEvents = _uiEvent.receiveAsFlow()
/** * Faza 30.6 — Shrani meritve v Firestore (batch write): * a) Posodobi profil z aktualnimi vrednostmi * b) Doda vnos v measurements_history (za grafe) * * Faza 30.8 — isSaving guard: klik na gumb med shranjevanjem se v celoti ignorira. * Faza 30.9 — napake se pošljejo kot BodyUiEvent.Error na Channel (→ Snackbar v UI). * * Klic chain: UI → VM → SaveBodyMeasurementsUseCase → BodyMeasurementsRepository → Firestore */ fun saveBodyMeasurements( shoulderCm: Double, waistCm: Double, hipCm: Double = 0.0, heightCm: Double = 0.0 ) { // Dvojni klik → prezri, če shranjevanje že teče if (_isSaving.value) return viewModelScope.launch { _isSaving.value = true try { val result = saveMeasurementsUseCase(shoulderCm, waistCm, hipCm, heightCm) result.onSuccess { android.util.Log.d("BodyModuleHomeVM", "✅ Meritve shranjene v zgodovino") _uiEvent.send(BodyUiEvent.SaveSuccess) } result.onFailure { e -> android.util.Log.e("BodyModuleHomeVM", "❌ Napaka pri shranjevanju meritev: ${e.message}") _uiEvent.send(BodyUiEvent.Error("Shranjevanje ni uspelo. Preverite povezavo.")) } } finally { // Vedno osvobodi, tudi ob nenapovedani izjemi _isSaving.value = false } } }
// ──────────────────────────────────────────────────────────────────────────
private val _ui = MutableStateFlow(BodyHomeUiState()) val ui: StateFlow<BodyHomeUiState> = _ui.asStateFlow()
private val _streakUpdatedEvent = MutableSharedFlow<StreakUpdateEvent>(extraBufferCapacity = 1) val streakUpdatedEvent: SharedFlow<StreakUpdateEvent> = _streakUpdatedEvent.asSharedFlow()
/** * Faza 23: Job tracking za LoadMetrics — vsak klic cancela prejšnjega. * Preprečuje race condition med vzporednimi Firestore branii. */ private var loadMetricsJob: Job? = null
fun handleIntent(intent: BodyHomeIntent) { when (intent) { is BodyHomeIntent.LoadMetrics -> { // Cancela morebitni prejšnji LoadMetrics — prepreči dvojno branje loadMetricsJob?.cancel() loadMetricsJob = viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true, errorMessage = null) try { getBodyMetrics.invoke(intent.email).collect { metrics -> if (metrics.isLoading) return@collect val todayIsRest = intent.plan?.weeks ?.flatMap { it.days } ?.firstOrNull { it.dayNumber == metrics.planDay } ?.isRestDay ?: false
_ui.value = _ui.value.copy( streakDays = metrics.streakDays, streakFreezes = metrics.streakFreezes, weeklyDone = metrics.weeklyDone, weeklyTarget = metrics.weeklyTarget, planDay = metrics.planDay, totalWorkoutsCompleted = metrics.totalWorkoutsCompleted, isWorkoutDoneToday = metrics.isWorkoutDoneToday, dailyKcal = metrics.dailyKcal, todayIsRest = todayIsRest, todayStatus = metrics.todayStatus, isLoading = false, errorMessage = metrics.errorMessage ) } } catch (e: Exception) { _ui.value = _ui.value.copy(errorMessage = e.message, isLoading = false) } } }
is BodyHomeIntent.CompleteRestDay -> { if (gamificationUseCase == null) { android.util.Log.w("BodyModuleHomeVM", "gamificationUseCase ni nastavljen — preskočim CompleteRestDay") return } viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true) try { val newStreak = gamificationUseCase.restDayInitiated() _ui.value = _ui.value.copy( isWorkoutDoneToday = true, streakDays = newStreak, todayStatus = UserDayStatus.REST_DAY_DONE, isLoading = false ) _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak, isRestDay = true)) } catch (e: Exception) { _ui.value = _ui.value.copy(isLoading = false, errorMessage = e.message) } } }
is BodyHomeIntent.HideCompletionAnimation -> _ui.value = _ui.value.copy(showCompletionAnimation = false)
is BodyHomeIntent.AcceptChallenge -> { /* lokalni state */ } is BodyHomeIntent.CompleteChallenge -> { /* lokalni state */ }
is BodyHomeIntent.SwapDays -> { // Faza 30.4: ViewModel kliče SAMO SwapPlanDaysUseCase — ne PlanDataStore. // Klic chain: VM → UseCase (validacija + lokalni model) → Repository → DataStore viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true, errorMessage = null) val lockedDay = if (_ui.value.isWorkoutDoneToday) _ui.value.planDay else null val res = swapPlanDays.invoke(intent.currentPlan, intent.dayA, intent.dayB, lockedDay) _ui.value = _ui.value.copy(isLoading = false) res.onSuccess { updatedPlan -> // Use case vrne posodobljeni model šele po uspešni Firestore transakciji intent.onResult(updatedPlan) } res.onFailure { e -> _ui.value = _ui.value.copy(errorMessage = e.message) } } }
is BodyHomeIntent.CompleteWorkoutSession -> { viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true, errorMessage = null) val isRestDay = _ui.value.todayIsRest val isExtra = intent.isExtraWorkout val oldPlanDay = _ui.value.planDay val oldWeeklyDone = _ui.value.weeklyDone
val result = updateBodyMetrics.invoke( email = intent.email, totalKcal = intent.totalKcal, totalTimeMin = intent.totalTimeMin, exercisesCount = intent.exerciseResults.size, planDay = oldPlanDay, isExtra = isExtra, exerciseResults = intent.exerciseResults, focusAreas = intent.focusAreas, isRestDay = isRestDay )
result.onSuccess { completionResult -> // Faza 23: Optimistični update iz WorkoutCompletionResult — brez dodatnega Firestore read-a. // moveToNextDay() je atomarno že zapisal vse podatke; streak + planDay sta znana. val todayStatus = when { isRestDay && isExtra -> UserDayStatus.REST_WORKOUT_DONE else -> UserDayStatus.WORKOUT_DONE } // Faza 31.6 avdit: moveToNextDay() vrne -1 ob Firestore napaki in 0 ob // de-dup preskohu. Oba primera filtered z takeIf { it > 0 }. // Fallback OHRANI STAR STREAK (ne poveča) — UI ne sme prikazovati lažnih vrednosti // medtem ko baza ni pisala. Ob vzpostavitvi omrežja getBodyMetrics stream // samodejno prinese pravo vrednost iz Firestorea. val newStreak = completionResult?.newStreakDays?.takeIf { it > 0 } ?: _ui.value.streakDays val newPlanDay = completionResult?.newPlanDay?.takeIf { it > 0 } ?: (oldPlanDay + if (!isExtra) 1 else 0) val newWeekly = if (todayStatus != UserDayStatus.REST_WORKOUT_DONE) (oldWeeklyDone + 1).coerceAtMost(_ui.value.weeklyTarget) else oldWeeklyDone
_ui.value = _ui.value.copy( streakDays = newStreak, weeklyDone = newWeekly, planDay = newPlanDay, isWorkoutDoneToday = true, todayStatus = todayStatus, showCompletionAnimation = !isExtra, isLoading = false ) _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak)) intent.onCompletion(completionResult) } result.onFailure { error -> _ui.value = _ui.value.copy(isLoading = false, errorMessage = error.message) intent.onCompletion(null) } } } } } }

